-- ============================================================
-- CHAPTER 1: Modal Mastery & Advanced Harmony
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, accuracy_threshold, estimated_minutes, is_premium) values

  ('a1c10000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000001',
   'Modal Interchange',
   'Borrow chords from parallel modes to create unexpected harmonic colors and emotional shifts.',
   1, 'theory',
   '{"intro":"Modal interchange (borrowed harmony) substitutes chords from parallel modes to add richness to diatonic progressions. Once you hear it, you will recognize it everywhere: The Beatles, Steely Dan, film scores, jazz standards.","steps":[{"title":"Parallel Modes Defined","body":"Every major key has a parallel minor sharing the same tonic: C major and C minor. Modal interchange borrows chords from parallel modes and uses them in the original key context. From Aeolian: bIII (Eb in C), bVI (Ab), bVII (Bb), and iv (Fm). These four chords alone transform diatonic progressions into something richer and emotionally complex. The borrowed chords carry the modal color of their source."},{"title":"The Borrowed iv Minor Subdominant","body":"The borrowed minor iv chord is the most emotionally potent interchange. In C major: F major (IV) to F minor (iv) to C major (I). The Ab note in Fm (b6 degree) pulls down by half-step to G (5th of C). This is the Beatles cadence from In My Life. Voice leading: Ab descends to G over a static C pedal, creating bittersweet, nostalgic resolution no purely diatonic progression can match."},{"title":"Common Borrowed Chord Progressions","body":"From Mixolydian: bVII (Bb in C) is blues-rock harmony foundation. From Dorian: major IV in minor (A major in E minor from Oye Como Va). From Phrygian: bII (Db in C) creates dark flamenco tension. The bVI-bVII-I progression (Ab-Bb-C) is the Mario cadence heard in countless film scores. It sounds triumphant because borrowed chords approach the tonic from below by whole step rather than from above by fifth."},{"title":"Voice Leading Across Modal Boundaries","body":"Key to intentional modal interchange: borrowed chord characteristic tones connect to surrounding diatonic tones by half-step or common tone. In C major, borrowing Ab (bVI): Ab resolves down to G, Eb resolves down to D (9th of C), and C is the common tone. Ab-G and Eb-D are half-step resolutions, the strongest voice leading, making borrowed chords feel inevitable and organic rather than random."}],"tips":["Practice I-iv-I and I-bVI-bVII-I in all 12 keys to internalize borrowed chord sounds","When soloing over modal interchange, target the color note (the scale degree differing from diatonic major) to make the modal shift audible","Record a I-IV-V loop and experiment with substituting borrowed chords from the parallel minor to train your ear"]}',
   null, null, 0, 45, true),

  ('a1c10000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000001',
   'Harmonic Minor',
   'The scale that defines classical minor tonality with its augmented second interval and dominant V chord.',
   2, 'theory',
   '{"intro":"The harmonic minor scale (natural minor with raised 7th) is the cornerstone of functional minor-key harmony. Its raised 7th provides the leading tone essential for authentic cadences. The augmented second between b6 and raised 7th gives it an exotic Middle Eastern quality.","steps":[{"title":"Construction and Intervals","body":"Harmonic minor: W-H-W-W-H-A2-H, where A2 = augmented second (3 semitones). A harmonic minor: A B C D E F G# A. The F to G# interval spans three semitones, the scale signature sound. On string 3: F at fret 10, G# at fret 13 requires a three-fret stretch. This wide leap is where the scale dramatic, Eastern quality lives under your fingers."},{"title":"The Dominant V Chord in Minor","body":"Without G# (raised 7th), the V chord in A minor is Em (E G B), a weak minor v lacking the leading tone gravitational pull. With G#: V becomes E major (E G# B), or E7 (E G# B D). Add b9 (F natural) for E7b9, the quintessential minor-key dominant containing both the leading tone (G#) pulling to A and the b9 (F) for tension."},{"title":"Harmonic Minor on Guitar","body":"A harmonic minor, position 1 at string 6 fret 5: frets 5-7-8 (A B C) string 6; 5-7-8 (D E F) string 5; 5-6-9 (G# A B) string 4. Irregular spacing: one-fret gap at G#-A and three-fret jump from A to B on string 4. Learn all five CAGED positions ascending and descending at 60 bpm, listening for interval quality."},{"title":"Harmony from Harmonic Minor","body":"Triads: i (Am), ii dim (B dim), bIII+ (C aug), iv (Dm), V (E major), bVI (F), vii dim (G# dim). Stack thirds on V: E G# B D F = E7b9, the harmonic minor signature dominant. Neo-classical metal (Yngwie Malmsteen, Ritchie Blackmore) is built almost entirely on harmonic minor and its 5th mode, Phrygian Dominant."}],"tips":["Practice A harmonic minor over an Am-E7 vamp to hear the G# creating essential harmonic minor tension","The augmented second leap (F to G#) requires a position shift; isolate just those two notes to internalize the wide interval","Harmonic minor is default for soloing over minor ii-V-i in jazz, providing altered dominant color natural minor cannot"]}',
   null, null, 0, 45, true),

  ('a1c10000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000001',
   'Melodic Minor',
   'The scale bridging classical convention and modern jazz, unlocking an independent harmonic universe through its seven modes.',
   3, 'theory',
   '{"intro":"The melodic minor scale is unique: classical tradition ascends with raised 6th and 7th (sounding like major with b3) and descends as natural minor. Jazz uses the ascending form in both directions, and its seven modes generate chord qualities unobtainable from the major scale.","steps":[{"title":"Classical vs. Jazz Melodic Minor","body":"Classical ascending in A: A B C D E F# G# A (W-H-W-W-W-W-H). The raised 6th (F#) eliminates harmonic minor awkward augmented second, creating a smoother line. Descending reverts to natural minor. Jazz ignores the descending change, making the scale an independent pitch collection with seven unique modes producing distinct chord qualities."},{"title":"The Seven Modes","body":"Mode I: Melodic Minor (m maj7 chord). Mode III: Lydian Augmented (maj7#5). Mode IV: Lydian Dominant (7#11, the tritone substitution scale). Mode VI: Locrian Natural 2 (m7b5 with natural 9). Mode VII: Super Locrian / Altered Scale (7alt containing b9, #9, b5, #5). G7alt = Ab melodic minor starting on G. This half-step-above relationship is one of the most important chord-scale connections in modern jazz."},{"title":"Melodic Minor on Guitar","body":"A melodic minor, position 1 at string 6 fret 5: 5-7-8 (A B C) string 6; 5-7-9 (D E F#) string 5; 5-7-9 (G# A B) string 4; 6-7-9 (C D E) string 3; 7-9-10 (F# G# A) string 2; 7-8-10 (B C D) string 1. F# to G# on string 2 (frets 7-9) is a smooth whole step, distinguishing it from harmonic minor. Learn all five CAGED positions."},{"title":"Harmonic Applications","body":"The tonic chord: m(maj7) = Am(maj7) = A C E G#, a haunting unresolved quality defining film noir and introspective jazz. Lydian Dominant (mode IV) over tritone substitutions: over Db7 resolving to Cmaj7, play Ab melodic minor for Db Lydian Dominant. Each mode of melodic minor maps to a specific chord type and function, forming the backbone of modern jazz chord-scale theory."}],"tips":["Learn melodic minor in all five CAGED positions as fingerings differ from both major and harmonic minor","Play Am(maj7) and listen to its haunting quality, the defining sound of melodic minor harmony","Apply the Altered Scale (mode VII) over any V7alt: play Ab melodic minor over G7alt for instant sophisticated outside tension"]}',
   null, null, 0, 45, true),

  ('a1c10000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000001',
   'Symmetric Scales Diminished and Whole Tone',
   'The symmetrical scaling systems essential for playing over altered and extended dominant chords.',
   4, 'theory',
   '{"intro":"Symmetric scales built from repeating interval patterns unlock tension over dominant chords that major and minor scales cannot reach. The diminished (octatonic) and whole-tone scales have dramatically fewer unique fingerings than diatonic scales, a significant advantage on guitar.","steps":[{"title":"The Two Diminished Scales","body":"Whole-half (W-H-W-H-W-H-W-H): A B C D Eb F Gb Ab, fits dim7 chords (A C Eb Gb). Half-whole (H-W-H-W-H-W-H-W) starting on E for E7b9: E F G G# A# B C# D, fits dominant 7b9 chords. Both are 8-note octatonic scales. Only 3 unique transpositions exist before the pattern repeats every 3 frets."},{"title":"Symmetry on the Fretboard","body":"Learn one 4-fret block of half-whole diminished at string 6 fret 0: 0-1-3 (E F G) string 6; 0-2-3 (A Bb C) string 5; 0-2-4 (C# D# E) string 4. Move to fret 3: same scale enharmonically. Move to fret 6: same. Move to fret 9: same. One pattern, four positions, full fretboard coverage. Dramatically less memorization than 12 diatonic scales times 5 positions."},{"title":"The Whole-Tone Scale","body":"6-note scale of only whole steps: C D E F# G# Bb. Only two unique whole-tone scales exist (C and C#/Db). On guitar: string 6 frets 8-10-12 (C D E); string 5 frets 9-11-13 (F# G# Bb). Produces augmented triads (C E G#) and dominant 7#5 chords. Complete absence of semitones creates floating, rootless, dreamlike quality. Debussy, Monk, and Oliver Nelson used it extensively."},{"title":"Inside-Outside Playing","body":"Sophisticated improvisers use symmetric scales as passing outside colors within diatonic frameworks. Pattern: diatonic over ii, switch to half-whole diminished over V, resolve diatonically on I. This inside-outside-inside contour creates thrilling tension that resolves satisfyingly. Coltrane, Holdsworth, and Metheny rely heavily on this diatonic-to-symmetric-and-back approach."}],"tips":["Practice half-whole diminished over a static E7 vamp to hear b9, #9, and #11 tensions immediately","Memorize 3 unique diminished fingerings and 2 whole-tone fingerings; symmetry makes this far less work than diatonic scales","Record a minor ii-V-i and alternate between harmonic minor (inside) and half-whole diminished (outside) on the V chord"]}',
   null, null, 0, 45, true),

  ('a1c10000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000001',
   'Modal Vamps and Progressions',
   'Compose and improvise over two-chord modal vamps in all seven diatonic modes, building fluency with each mode sound.',
   5, 'exercise',
   '{"intro":"The best way to internalize modal sounds is through two-chord vamps establishing each mode as a tonal center. Play through modal vamps for all seven diatonic modes and improvise melodies highlighting each mode characteristic note.","steps":[{"title":"Ionian: I-IV (Cmaj7-Fmaj7)","body":"Cmaj7 (x32000) and Fmaj7 (x33210) as a two-bar loop. Improvise in C major. Target the major 7th (B at string 2 fret 12) held against the chord for that pretty Ionian color. Ionian is bright, stable, and home; every other mode is heard as a variation from this baseline."},{"title":"Dorian: i-IV (Dm7-G7)","body":"Dm7 (x57565) and G7 (353433). The raised 6th (B natural in D Dorian) is the mode-defining note. Over Dm7, target B (string 1 fret 7) against the minor triad. Dorian is minor with a soulful, optimistic lift. Santana, Allman Brothers, and funk music live in Dorian."},{"title":"Phrygian: i-bII (Em-Fmaj7)","body":"Em (022000) and Fmaj7 (133210). The bII resolving to i creates dark Spanish-flamenco tension. Solo in E Phrygian targeting the b2 (F) and b6 (C). The closely voiced open Em to F shift (only open low E moves to F at string 6 fret 1) creates unmistakable Phrygian sonority."},{"title":"Lydian: I-II (Cmaj7-D/C)","body":"Cmaj7 (x32000) and D/C (x30232). Raised 4th (F#) is Lydian defining tone. Hold F# (string 1 fret 14) against Cmaj7. Lydian feels floating, luminous, exalted. Steve Vai and Joe Satriani built careers on Lydian vamps. The #4 creates pleasant tension that never demands resolution."},{"title":"Mixolydian: I-bVII (G7-F/G)","body":"G7 (320001) and F/G (3x3211). The b7 (F natural) is Mixolydian signature: the dominant seventh that feels like home. Target F (string 1 fret 13) over G7. Mixolydian is blues-rock, funk, and Grateful Dead territory: major with lowered seventh, grounded and earthy."}],"tips":["Record each vamp for 3-5 minutes and improvise without stopping; let your ear guide you to each mode characteristic note","Sing short melodic phrases before playing them to forge the connection between inner ear and modal sound","Practice each vamp at multiple fretboard positions; the same Dorian vamp at position 5 sounds different from position 10"]}',
   null, null, 75, 50, true);

-- ============================================================
-- CHAPTER 2: Jazz Guitar Fundamentals
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, accuracy_threshold, estimated_minutes, is_premium) values

  ('a1c20000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000002',
   'Extended Voicings 9ths 11ths 13ths',
   'Build rich jazz chords by stacking thirds beyond the seventh to create lush, colorful voicings.',
   1, 'chord',
   '{"intro":"Extended chords are the signature sound of jazz guitar. By adding the 9th, 11th, and 13th to seventh chords, you create the complex sonorities defining the genre. Full 13th chords are rarely played with all seven notes; voice leading and finger economy dictate which extensions make the cut.","steps":[{"title":"Major 9th and Dominant 9th","body":"Cmaj9 (x3243x): root string 5 fret 3 (C), maj7 string 4 fret 2 (B), 9th string 3 fret 4 (D), 3rd string 2 fret 5 (E). Strings 6 and 1 muted. The 9th (D) voiced above the 7th produces the classic jazz guitar sound. C9 (x3233x): dominant 7th (Bb) on string 4, 9th (D) on string 3, 3rd (E) on string 2. Major 9th is shimmering and reflective; dominant 9th is bluesy and funky."},{"title":"Minor 9th Chord","body":"Am9 (5x5557): root string 6 fret 5 (A), b7 string 4 fret 5 (G), b3 string 3 fret 5 (C), 9th string 2 fret 5 (B), 5th string 1 fret 5 (E). A partial barre at fret 5 makes this shape movable to any key. The m9 is the quintessential soul-jazz chord from Grant Green and George Benson. The major 7th interval between b3 (C) and 9th (B) creates bittersweet complexity."},{"title":"11th and Sus Chords","body":"Full 11th chords are rare: the 11th clashes with the major 3rd in close voicing. G7sus4 (3x3211) is essentially an 11th without the 3rd. Am11 (5x5533): root A, b7 G, b3 C, 11 D (string 2 fret 3), 5 E. The 11th adds suspended, open quality that can resolve downward to the 3rd in Herbie Hancock style inner voice movement."},{"title":"13th Chord","body":"C13 (8x8910x): root string 6 fret 8 (C), b7 string 4 fret 8 (Bb), 3rd string 3 fret 9 (E), 13th string 2 fret 10 (A). The 5th, 9th, and 11th omitted. Cmaj13 (8x998x): root C, 3rd E, maj7 B, 13th A. The 13th has a luminous, cinematic quality, the chord of lush ballads and classic bossa nova. The stretch across frets 8-10 requires careful finger placement."}],"tips":["Build extended chords by first mastering shell voicings (root-3rd-7th), then add one extension at a time for systematic learning","When comping in a band, omit root and 5th; the bassist covers root and 5th adds no color; focus on 3rd, 7th, and chosen extension","Transpose each voicing chromatically up the neck; a maj9 shape at frets 3, 5, 7, 8, 10, 12 trains both ear and hand"]}',
   'CMaj9', '[{"string": 5, "fret": 3, "finger": 1}, {"string": 4, "fret": 2, "finger": 1}, {"string": 3, "fret": 4, "finger": 3}, {"string": 2, "fret": 5, "finger": 4}, {"string": 6, "fret": 0, "finger": 0, "muted": true}, {"string": 1, "fret": 0, "finger": 0, "muted": true}]', 80, 50, true),

  ('a1c20000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000002',
   'Jazz Comping Drop 2 and Drop 3',
   'Master the essential jazz guitar voicing technique for smooth voice leading through progressions.',
   2, 'exercise',
   '{"intro":"Drop voicings are the practical foundation of jazz guitar harmony. Dropping one voice from a close-position chord down an octave creates guitar-friendly spacing with clearer voice leading. Drop-2 and drop-3 cover virtually all standard jazz comping scenarios and are the voicings of every jazz guitarist from Freddie Green to Kurt Rosenwinkel.","steps":[{"title":"Drop-2 Construction","body":"Start with a close-voiced 7th chord (all notes within one octave). Drop the second voice from the top down one octave. Close Cmaj7 top to bottom: B-C-E-G (7th-root-3rd-5th). Drop root (voice 2): C drops an octave, result C-B-E-G, creating a wide gap between root and closely-voiced upper voices. Four distinct inversions per chord quality on adjacent string sets."},{"title":"Drop-2 on Strings 1-4","body":"Cmaj7 root-position drop-2: x-3-5-4-5-x (string 5=C root, string 4=G 5th, string 3=B 7th, string 2=E 3rd). First inversion: x-5-5-5-6-x. Second inversion: x-7-9-8-8-x. Third inversion: x-10-9-9-12-x. Learn all four inversions for maj7, dom7, m7, and m7b5, then transpose around the cycle of fourths."},{"title":"Voice Leading Through ii-V-I","body":"Apply drop-2 to ii-V-I in C: Dm7 (x5756x) to G7 (x5546x) to Cmaj7 (x3545x). The 7th of Dm7 (C, string 2 fret 5) resolves down half-step to 3rd of G7 (B, string 2 fret 4). The 7th of G7 (F, string 1 fret 6) resolves down half-step to 3rd of Cmaj7 (E, string 1 fret 5). This half-step guide-tone resolution IS functional harmony. Practice in all 12 keys."},{"title":"Rhythmic Comping Patterns","body":"Apply the Charleston rhythm (dotted quarter + eighth on beat 1 and and-of-2), anticipations (chord an eighth before the downbeat), and Freddie Green quarter-note pulse (four even muted strums per bar). Record a walking bass line on beats 1 and 3 while comping on beats 2 and 4, simulating playing with a bassist."}],"tips":["Practice drop voicings around the cycle of fourths to move shapes around the neck rather than memorizing rote in one key","Focus on 3rd and 7th of each chord; these guide tones alone imply the entire chord quality and are the primary voice leading targets","Transcribe one chorus of Joe Pass, Jim Hall, or Ed Bickert comping and analyze which voicings and string sets they favor"]}',
   null, null, 75, 55, true),

  ('a1c20000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000002',
   'ii-V-I Progressions',
   'The fundamental harmonic building block of jazz: analyze, voice, and internalize the ii-V-I in all keys and substitutions.',
   3, 'theory',
   '{"intro":"The ii-V-I is to jazz what I-IV-V is to blues: the central harmonic cell. Understanding its function, voicing, and substitutions is the single most important step in becoming fluent in jazz guitar.","steps":[{"title":"Diatonic ii-V-I in Major","body":"In C: Dm7 (ii) to G7 (V) to Cmaj7 (I). Function: ii (supertonic, subdominant) sets up V (dominant, tension), which resolves to I (tonic, home). Essential voice leading: 7th of Dm7 (C) moves down half-step to 3rd of G7 (B); 7th of G7 (F) resolves down half-step to 3rd of Cmaj7 (E). This descending chromatic guide-tone line is the melodic thread making the progression logical and inevitable."},{"title":"Minor ii-V-i","body":"In A minor: Bm7b5 (ii) to E7b9 (V) to Am7 (i). The ii is half-diminished (B D F A) with b5 as key tension. V takes b9 (F natural). Solo over ii with A natural minor, over V with A harmonic minor (containing G# leading tone), over i with A natural minor. The minor ii-V-i is darker, weightier, carrying greater emotional gravity than its major counterpart."},{"title":"Tritone Substitution","body":"Replace V (G7) with a dominant a tritone away: Db7. Why it works: Db7 shares G7 guide tones. 3rd of G7 (B) = 7th of Db7 (Cb enharmonically). 7th of G7 (F) = 3rd of Db7. Smooth chromatic bass line: Dm7 to Db7 to Cmaj7 (D-Db-C in half-step descent). The tritone substitution is the most common jazz alteration to ii-V-I."},{"title":"Backdoor ii-V and Coltrane Changes","body":"Backdoor: Fm7 to Bb7 to Cmaj7 (iv-bVII-I), a modal interchange variant targeting tonic from parallel minor. Coltrane changes (Giant Steps): interpolate V-I cadences moving by major thirds, creating symmetrical octave division. Understanding this requires mastery of all 12 keys, the ultimate ii-V-I challenge."}],"tips":["Practice ii-V-I voicings in all 12 keys around the cycle of fourths, focusing on 7th-to-3rd resolution","Sing the guide tone lines (7 to 3, then 7 to 3) through every ii-V-I while playing to internalize the pattern in your ear","Transcribe the comping of one chorus from Autumn Leaves or Four on Six and map every chord to its ii-V-I function"]}',
   null, null, 0, 45, true),

  ('a1c20000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000002',
   'Bebop Language and Chromaticism',
   'Learn the vocabulary of bebop: chromatic passing tones, enclosures, approach notes, and the bebop scales that make lines swing.',
   4, 'theory',
   '{"intro":"Bebop is the mother tongue of modern jazz improvisation. Its defining characteristic is chromaticism: passing tones, approach notes, and enclosures transforming diatonic lines into propulsive, rhythmically sophisticated statements. This is not about memorizing licks but internalizing a systematic method of chromatic decoration.","steps":[{"title":"The Bebop Scales","body":"Bebop dominant: add chromatic passing tone between b7 and root. G A B C D E F F# G (added major 7th F#). This 8-note scale ensures chord tones (G B D F) fall on downbeats when playing continuous eighth notes. Bebop major: add #5 passing tone C D E F G G# A B C. Bebop Dorian: add major 3rd passing tone between b3 and 4: D E F F# G A B C D. Rhythmic alignment of harmony and meter is the core purpose."},{"title":"Chromatic Approach Notes","body":"The simplest bebop device: approach any chord tone from a half-step below or above on a weak beat (the and), resolving to the target on a strong beat (downbeat). Target E (3rd of Cmaj7) on beat 1: play Eb or F on the and of beat 4. Chromatic from below implies leading tone; from above creates darker tension. Combine both: Eb then F then land on E for a double chromatic approach."},{"title":"Diatonic and Chromatic Enclosures","body":"An enclosure surrounds the target note before landing. Target E: play F (diatonic above) to D (diatonic below) to E. More elaborate: C (third below) to F (whole step above) to D# (chromatic below) to E, a four-note enclosure. Charlie Parker used 3-5 note enclosures as primary vocabulary. The enclosure is a device, not a lick; apply it to any chord tone in any key."},{"title":"Rhythmic Placement The Secret of Swing","body":"Bebop chromaticism only sounds like bebop when placed correctly. Chromatic approaches start on offbeats; target chord tones land on downbeats. Chord tones (1 3 5 7) on downbeats, passing/approach tones on upbeats. When aligned, lines swing automatically. The rhythmic hierarchy of downbeat=strong/upbeat=weak perfectly mirrors the harmonic hierarchy of chord tone=stable/non-chord tone=unstable. This is the design principle."}],"tips":["Practice bebop dominant starting on each chord tone to reveal how the chromatic passing tone shifts relative to the beat","Transcribe 8 bars of a Charlie Parker solo and circle every chromatic note, identifying each as passing tone, approach note, or enclosure","Practice enclosures on a single chord tone for 5 minutes before attempting full progressions"]}',
   null, null, 0, 40, true),

  ('a1c20000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000002',
   'Walking Bass Lines',
   'Play walking bass lines on lower strings while comping chords above: the essential skill for solo jazz guitar.',
   5, 'exercise',
   '{"intro":"Walking bass lines on guitar combine bassist and chordal accompanist into one instrument. This is the technique of Joe Pass, Tuck Andress, and Martin Taylor. It requires thumb-finger independence, precise time feel, and deep harmonic knowledge.","steps":[{"title":"The Basic Quarter-Note Walk","body":"Over ii-V-I in C, play quarter-note roots: D (string 5 fret 5), G (string 6 fret 3), C (string 5 fret 3), one note per beat. Use thumb rest stroke for fullest tone. Walking bass must swing: first and third beats emphasized, creating the doo-BAH-doo-BAH lilt. Practice with metronome clicking on beats 2 and 4 to internalize swing feel."},{"title":"Chord Tones and Chromatic Approaches","body":"Expand beyond roots. For Dm7 to G7: beat 1 D (root), beat 2 F (3rd), beat 3 A (5th), beat 4 Ab (chromatic approach to G). For G7 to Cmaj7: beat 1 G, beat 2 B (3rd), beat 3 D (5th), beat 4 Db (chromatic approach to C). The root-chord tone-chord tone-chromatic approach formula is the most common walking bass pattern. Chromatic on beat 4 creates forward motion."},{"title":"Bass and Chord Integration","body":"Add chords on beats 2 and 4 while bass walks on all four beats. Beat 1: thumb plays D bass. Beat 2: fingers play Dm7 shell voicing upper voices. Beat 3: thumb plays F bass. Beat 4: fingers play G7 shell voicing. The Charleston rhythm (bass on 1 and 3, chords on 2 and 4) is the fundamental solo guitar texture. Practice at 60 bpm until thumb and fingers feel independent."},{"title":"Walking Through a Standard","body":"Apply to Autumn Leaves in Gm: Cm7-F7-Bbmaj7-Ebmaj7-Am7b5-D7-Gm. Walk quarter-note bass through circle-of-fourths while comping on beats 2 and 4. Between Bbmaj7 and Ebmaj7: bass can walk Bb-C-D-Eb (stepwise) or Bb-Ab-Gb-Eb. The bass line should feel like a melody in the bass register."}],"tips":["Practice bass line alone with metronome on beats 2 and 4 to internalize swing feel independently from chordal playing","Record bass line and comp over it; this reveals rhythmic inconsistencies between thumb and fingers","Listen to Joe Pass Virtuoso albums; transcribe just the bass line from four bars"]}',
   null, null, 75, 55, true);

-- ============================================================
-- CHAPTER 3: Advanced Lead & Soloing
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, accuracy_threshold, estimated_minutes, is_premium) values

  ('a1c30000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000003',
   'Legato Technique',
   'Develop fluid hammer-ons, pull-offs, and slides for seamless, vocal-like phrasing across the fretboard.',
   1, 'exercise',
   '{"intro":"Legato technique (playing notes through hammer-ons and pull-offs rather than picking each one) is the foundation of fluid, vocal-style soloing, the primary articulation of Allan Holdsworth, Joe Satriani, and Brett Garsed. This lesson builds legato strength, evenness, and control across all strings and positions.","steps":[{"title":"Two-Note Hammer-On Drills","body":"Fret string 3 fret 5 with finger 1 (C). Pick, then hammer on to fret 7 with finger 3 (D) using only finger velocity, no second pick. The hammered note must equal the picked note in volume. Practice at distances: 5 to 7 (whole step), 5 to 8 (minor third), 5 to 9 (major third) across all strings. Further distance requires more finger velocity."},{"title":"Pull-Off Drills","body":"Fret both notes simultaneously: finger 3 at string 3 fret 7 (D) and finger 1 at fret 5 (C). Pick the higher note, then pull finger 3 off with a downward flick (a plucking motion, not simply lifting). The pulled-off note must match the picked note in volume. This downward-and-away flick takes weeks to develop consistently."},{"title":"Three-Note-Per-String Legato Runs","body":"A natural minor at position 5. String 6 frets 5-7-8 (A B C): pick first note only, hammer second and third. Reverse: pick highest, pull off to lower notes. Combine: pick once per string, hammer the remaining two notes ascending, pull-off descending. Target: every note perfectly equal in volume, timing, and clarity."},{"title":"Legato Across String Changes","body":"The hardest legato challenge: crossing strings without picking. Use the diagonal slide. String 3 fret 7 (D), hammer to fret 9 (E with finger 4), then slide finger 4 diagonally to string 2 fret 10 (A). Smooth and clear destination note. This diagonal slide is the technique enabling all-legato playing across the entire fretboard."}],"tips":["Legato volume comes from finger velocity, not strength; snap the hammer-on finger down as fast as possible","Rest picking hand on strings near bridge for muting; uncontrolled string resonance is legato biggest enemy","Practice on acoustic or unplugged electric; higher string tension builds finger strength faster than low-action electric"]}',
   null, null, 80, 55, true),

  ('a1c30000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000003',
   'Advanced Bending and Vibrato',
   'Master pre-bends, release bends, unison bends, and vocal-quality vibrato: the techniques giving your playing its signature voice.',
   2, 'exercise',
   '{"intro":"Bending and vibrato are the guitarist equivalent of vocal inflection and tremolo. These are not decorative; they are the primary carriers of emotion in electric guitar. Advanced bending means microtonal pitch control. Advanced vibrato means varying width, speed, and shape intentionally.","steps":[{"title":"Precision Bending","body":"Bend string 2 fret 15 (D) up a whole step to E. Verify against string 1 fret 12 (must be perfect unison, zero beating). Half-step to D#: verify against string 1 fret 11. Quarter-step microtonal inflection between D and D#. Use tuner: +50 cents quarter, +100 half, +200 whole. Landing bends dead on pitch every time separates advanced from intermediate."},{"title":"Pre-Bends and Release Bends","body":"Pre-bend string 3 fret 14 (A#) silently up a whole step to C target. Pick, then slowly release. The listener hears pitch descending from nowhere, a ghostly vocal effect. Combine: pre-bend, pick (pitch falls), then immediately bend back up (pitch rises). This dip mimics a singer scooping into a note. Practice until completely smooth."},{"title":"Unison Bends","body":"Fret string 1 fret 15 (G) and simultaneously bend string 2 fret 18 (E) up a minor third to G. Both strings at identical pitch, a chorused vocal doubling effect. Bent pitch must match fretted pitch with absolute precision. Jimi Hendrix (Little Wing) and SRV made unison bends a signature. Support bends with multiple fingers."},{"title":"Vibrato Three Parameters","body":"Width: narrow (classical, refined) to wide (blues, dramatic). Speed: slow (ballad, spacious) to fast (intense, urgent). Shape: sine wave (smooth, vocal) to square wave (aggressive, rhythmic). Practice each combination. Vibrato originates from wrist rotation, not finger wiggling. Pitch oscillates equally above AND below target."}],"tips":["Always use multiple fingers to support a bend; fingers 1 and 2 behind finger 3 on the same string","Practice bends with tuner 5 minutes daily; landing on pitch without overshooting requires ear training as much as hand training","Record vibrato in isolation; uneven vibrato is the number one tell of an intermediate guitarist"]}',
   null, null, 80, 50, true),

  ('a1c30000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000003',
   'Sweep Picking Fundamentals',
   'Build coordination for arpeggio sweeps, the technique behind Yngwie Malmsteen, Frank Gambale, and Jason Becker.',
   3, 'exercise',
   '{"intro":"Sweep picking moves the pick in a single continuous motion across adjacent strings, producing arpeggios at speeds impossible with alternate picking. It requires absolute synchronization between hands and disciplined, metronomic practice. This lesson builds from the sweeping motion to three-string and five-string arpeggios.","steps":[{"title":"The Sweeping Motion","body":"The pick descends across strings in one smooth raking motion, like strumming a chord in extreme slow motion, but each note sounding individually. Critical: the pick glides through each string and rests on the next, never rebounding. Practice Am arpeggio on three strings at fret 5: string 3 (C), string 2 (E), string 1 (A), all one downward stroke. Each note separately voiced, no two ringing simultaneously."},{"title":"Three-String Minor and Major Sweeps","body":"Am sweep descending: pick string 3 fret 5 (C b3), string 2 fret 5 (E 5th), string 1 fret 5 (A root). Ascending: continuous upstroke string 1 to 2 to 3. Add hammer-on from fret 5 to 8 on string 1 (A to C) after descending sweep, pull-off descending. Practice at 60 bpm; cleanly articulated separate notes take absolute priority over speed."},{"title":"The Rolling Technique","body":"When consecutive sweep notes share the same fret across adjacent strings, roll the fretting finger: slightly release pressure on the already-played string while maintaining pressure on the next. One finger bars three strings at fret 5; as the pick descends, the finger rocks across strings. This prevents notes from bleeding together."},{"title":"Five-String Sweep Arpeggios","body":"Am sweep strings 5 through 1: string 5 fret 12 (A root), string 4 fret 10 (C b3), string 3 fret 9 (E 5th), string 2 fret 10 (A octave), string 1 fret 12 (C). Hand shifts during sweep. Index covers strings 3-4, ring/pinky handle strings 5, 2, and 1. Practice left hand alone first, then add right-hand sweep at very slow tempo."}],"tips":["Practice at tempo where every note has identical volume and duration; if one note is quieter, you are going too fast","Record yourself and listen for bleeding: two notes ringing simultaneously is the most common sweep error","Use clean tone while practicing; distortion masks uneven picking; clean sweeps unplugged will sound incredible amplified"]}',
   null, null, 85, 60, true),

  ('a1c30000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000003',
   'Economy Picking',
   'Combine alternate picking with sweep-like motions when changing strings: the technique of Frank Gambale and fusion guitarists.',
   4, 'exercise',
   '{"intro":"Economy picking combines alternate picking (down-up on one string) with directional picking when crossing strings (continuing the same direction like a mini-sweep). This hybrid reduces wasted motion and can increase speed 20-30% over strict alternate picking. It is the dominant right-hand technique in modern fusion and progressive metal.","steps":[{"title":"The Economy Picking Rule","body":"Moving to a higher (thinner) string: continue pick in the same direction. Moving to a lower (thicker) string: alternate as usual. Result: descending uses consecutive downstrokes (mini-sweep); ascending uses consecutive upstrokes. Same-string notes always alternate. This eliminates the wasted skip motion over adjacent strings."},{"title":"Two-String Economy Patterns","body":"A minor at position 5, three notes per string. String 2 frets 5-7-8 (E F G) then string 1 frets 5-7-8 (A B C). Economy: D-U-D on string 2, continue downstroke through change, D-U-D on string 1. Three consecutive downstrokes across the boundary. Descending: U-D-U on both strings. The pick sweeps straight through."},{"title":"Inside vs. Outside String Crossing","body":"Inside crossing (lower to higher after upstroke): pick is between strings, sweep feels natural. Outside crossing (lower to higher after downstroke): pick is above the lower string, must jump. Deploy economy for inside crossings, alternate for outside crossings. Learn to recognize which scenario applies in real time."},{"title":"Full-Scale Economy Picking","body":"G major scale three notes per string across all six strings. Ascending: (D-U-D) repeated each string, D continuing through changes. Descending: (U-D-U) repeated. At 100 bpm sixteenth notes, fluidity difference versus alternate picking is dramatic: economy feels like one continuous motion across the entire fretboard."}],"tips":["Practice at 50% of alternate picking max speed; goal is rhythmic evenness indistinguishable from alternate picking","Draw picking pattern diagrams (D and U symbols) for scales to build conscious awareness of when to economy-pick","Watch Frank Gambale instructional videos; observe how little his wrist moves compared to alternate pickers"]}',
   null, null, 80, 50, true),

  ('a1c30000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000003',
   'Phrasing Like a Vocalist',
   'Construct solos that breathe, tell stories, and use space: the art of melodic phrasing over technical display.',
   5, 'exercise',
   '{"intro":"The most memorable solos (David Gilmour Comfortably Numb, B.B. King The Thrill Is Gone, George Harrison Something) are memorable not for speed but because the guitarist phrases like a singer. Every phrase breathes. Every note has intention. This lesson teaches the architecture of vocal phrasing: space, contour, motif development, and narrative arc.","steps":[{"title":"The Breath Phrase","body":"Singers must breathe; guitarists do not have to, and that is the problem. Impose breath-length constraints: play a phrase of 2-4 seconds (a singer breath), then leave 2-4 seconds of silence. Over slow blues in A: four beats of melody, four beats of rest. Repeat. The silence is where the audience absorbs your phrase; it is as much part of the music as the notes."},{"title":"Motivic Development","body":"A motif is a short melodic-rhythmic idea (3-8 notes). Develop through: repetition, transposition (same rhythm, different pitches), inversion (ascending becomes descending), augmentation (expand note values), diminution (compress), fragmentation (use only part). This makes solos coherent. Start with three-note motif and develop across 8 bars using four different transformations."},{"title":"Rhythmic Displacement","body":"Take a simple phrase and shift its starting point: from beat 1 to beat 2, or the and of beat 4, or beat 3. Same melodic content acquires completely different character when displaced against meter. This makes phrases feel behind the beat (laid-back, bluesy) or on top (urgent, driving). Practice displacing a one-bar lick to start on every sixteenth-note subdivision."},{"title":"Building a Narrative Arc","body":"A solo needs beginning, middle, and end. Beginning: state theme simply, lower register, with space. Middle: develop motif, increase density, higher registers, introduce tension. Climax: emotional peak, highest note, fastest phrase, most intense vibrato. End: resolution, return to original motif, descend, slow down, leave space. Map out a 12-bar blues solo with this explicit three-part arc."}],"tips":["Before playing any phrase, sing it aloud first; if you cannot sing it, you are thinking with fingers rather than ear","Record solos and listen back without guitar; ask honestly: does this hold my attention purely as a listener?","Study vocalists, not just guitarists; transcribe Aretha Franklin, Frank Sinatra, and Billie Holiday phrasing"]}',
   null, null, 75, 45, true);

-- ============================================================
-- CHAPTER 4: Classical Guitar & Notation
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, accuracy_threshold, estimated_minutes, is_premium) values

  ('a1c40000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000004',
   'Standard Notation Reading',
   'Develop fluent reading of standard musical notation on guitar, opening the door to the entire classical, jazz, and film score repertoire.',
   1, 'theory',
   '{"intro":"Reading standard notation on guitar is complex because identical pitches can be played in multiple fretboard positions. This lesson provides a systematic method for mapping the treble staff to the fretboard and developing reading fluency from open position through the 12th fret.","steps":[{"title":"Guitar as Transposing Instrument","body":"The guitar sounds one octave lower than written. Middle C is notated on the first ledger line below the treble staff but played at string 2 fret 1 or string 3 fret 5. All guitar music is written in treble clef one octave higher than concert pitch. Understanding this prevents confusion when reading with piano or other concert-pitch instruments."},{"title":"Open Position Reading","body":"Map every natural note from open strings to fret 4. String 6 open = E (third ledger line below staff). String 5 open = A (second space). String 4 open = D (fourth line). String 3 open = G (second line from top). String 2 open = B (middle line above staff). String 1 open = E (top space). Practice Sor Op. 60 and Carcassi Op. 59 studies in first position at slow tempo, saying note names aloud."},{"title":"Position Reading Beyond First","body":"Guitar positions numbered by fret: I = frets 1-4, V = frets 5-8 (most important intermediate position). Identify which position a passage lies in based on highest and lowest notes. Practice reading the same C major scale melody in positions I, III, V, and VII; each yields entirely different fingerings."},{"title":"Rhythmic Reading","body":"Practice the 10 rhythmic archetypes using a single pitch (open G), playing only rhythm as written. Set metronome to click on beats 2 and 4 while reading. Count subdivisions aloud: 1-e-and-a 2-e-and-a. Vocalizing subdivisions reinforces rhythmic accuracy more effectively than silent counting."}],"tips":["Practice sight-reading 15 minutes daily; consistency matters more than duration; professionals lose fluency after days of neglect","Start with music far below technical level; reading is about instant recognition, not technical challenge","Use look-ahead technique: while playing beat 1, eyes should be scanning beat 3"]}',
   null, null, 0, 45, true),

  ('a1c40000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000004',
   'Classical Right Hand Technique',
   'Master rest stroke, free stroke, arpeggio patterns, and nail shaping: the foundation of classical guitar tone production.',
   2, 'exercise',
   '{"intro":"Classical guitar technique is defined by the right hand. The p-i-m-a system (thumb=pulgar, index=indice, middle=medio, ring=anular) produces a palette of articulations and tonal colors unmatched by plectrum. This lesson establishes proper position, stroke mechanics, and fundamental Giuliani arpeggio patterns.","steps":[{"title":"Right Hand Position and Nail Shaping","body":"Right hand hovers over soundhole with relaxed, slightly arched wrist. Fingers contact strings at 45 degrees where flesh meets nail simultaneously. File nails following fingertip contour; nail extends 1-2mm beyond fingertip with rounded shape. Polish with 400 then 1200 grit. Smooth nails produce pure tone; rough nails produce scratchy attack. Flesh provides warmth; nail provides projection and clarity."},{"title":"Rest Stroke (Apoyando)","body":"The rest stroke produces the fullest, roundest classical tone. Push the finger through the string toward the soundboard, coming to rest on the adjacent lower string. The motion is a push into the guitar, not a pluck away. Main knuckle drives motion; middle and tip joints remain passive. Practice on each string individually, listening for bell-like ring with zero nail click."},{"title":"Free Stroke (Tirando)","body":"Free stroke is for arpeggios, chords, and polyphonic textures. Finger plucks string and follows through into palm, clearing adjacent strings. Free strokes are lighter and brighter than rest strokes. Practice arpeggios with all free strokes first, then selectively use rest strokes on melody notes within arpeggios for dynamic contrast."},{"title":"Giuliani 120 Right Hand Studies","body":"Pattern 1: p-i-m-a on strings 6-3-2-1. Pattern 2: p-i-m-a-m-i. Pattern 3: p-a-m-i (reverse). Practice each on Em or Am at 60 bpm with metronome. Thumb plucks from main joint; each finger must produce absolutely identical tone and volume. Listen for the balanced, harp-like quality of a perfectly even arpeggio."}],"tips":["Shape and polish nails before every practice session; nails grow 0.1mm per day and this noticeably affects tone","Practice right-hand patterns on open strings during other activities; make p-i-m-a completely automatic","Record tone weekly; listen for nail click (nail too long), thin tone (too much nail), or dull tone (too much flesh)"]}',
   null, null, 80, 55, true),

  ('a1c40000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000004',
   'Renaissance and Baroque Studies',
   'Play authentic repertoire from Renaissance lute and Baroque guitar: Dowland, Bach, Sanz, and Weiss adapted for modern guitar.',
   3, 'exercise',
   '{"intro":"The classical guitar ancestors produced a vast repertoire transferring beautifully to the modern instrument. This lesson explores stylistic conventions, ornamentation, and landmark works of the 16th-18th centuries.","steps":[{"title":"Renaissance Lute: John Dowland","body":"Dowland fantasias and galliards (c.1590-1610) are pinnacles of English Renaissance polyphony. Lachrimae Pavan features 2-3 independent contrapuntal voices. Key features: dance-derived rhythms (pavan=slow duple, galliard=lively triple), single-stroke divisions for ornamentation, and imitative entries where bass melodic fragments must be audible against ongoing upper voices."},{"title":"Gaspar Sanz and Spanish Baroque","body":"Sanz Instruccion de musica sobre la guitarra espanola (1674) is the foundational Baroque guitar treatise. Learn Canarios and Espanioleta, dances on ground bass patterns. Sanz alternates between strummed (rasgueado) and plucked (punteado) textures, central to authentic Baroque guitar style."},{"title":"J.S. Bach Adapted for Guitar","body":"Bach lute suites (BWV 995-1000) and unaccompanied cello works translate idiomatically. Begin with Prelude from Cello Suite No.1 (BWV 1007) in D major (drop D). The Prelude is an unbroken arpeggiated stream; your task is to voice each chord so the progression is clear. Bouree from BWV 996 (E minor, often A minor on guitar) teaches contrapuntal thinking."},{"title":"Period Performance Practice","body":"Baroque trills start on upper auxiliary note, not principal. Appoggiaturas take half the main note value, played on the beat. French notes inegales: consecutive eighth notes played with subtle swing (long-short) even when notated evenly. These conventions are as fundamental as swing eighth notes are to jazz."}],"tips":["Use capo at fret 2 or 3 for Renaissance lute music to approximate the original instrument shorter scale and brighter timbre","Listen to lutenists (Paul O Dette, Nigel North) rather than guitarists for Renaissance repertoire phrasing conventions","When arranging Bach, bass line must be as clear as melody; often means simplifying inner voices to avoid lower register muddiness"]}',
   null, null, 80, 55, true),

  ('a1c40000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000004',
   'Transcription Skills',
   'Develop the ability to notate music by ear: transcribe melodies, chord progressions, and full arrangements from recordings.',
   4, 'exercise',
   '{"intro":"Transcription (writing down music you hear) is the single most powerful ear-training tool available. It forces microscopic listening, vocabulary internalization, and direct ear-to-notation connection. This lesson provides systematic methods for transcribing at increasing levels of complexity.","steps":[{"title":"Tools and Workflow","body":"Essential: slowdown app (Amazing Slow Downer, Transcribe, or any DAW), notation software (MuseScore is free), tuner, and keyboard for pitch reference. Workflow: isolate 2-4 bars, loop at 50-75% speed, sing it back without recording, find notes on guitar, then notate. Never listen and notate simultaneously. Three passes: pitch first, rhythm second, articulation third."},{"title":"Transcribing Melodies","body":"Start with simple familiar melodies. Process: (1) identify key by finding tonal center. (2) Determine scale. (3) Sing first note, match on guitar, notate. (4) For each subsequent note: determine direction and interval size. (5) Write rhythm while tapping foot. Practice with Happy Birthday before unfamiliar material."},{"title":"Transcribing Chords","body":"Step 1: transcribe bass line (lowest note of each chord). Step 2: identify chord quality (major=bright, minor=dark, dominant=tense). Step 3: listen for extensions (7ths, 9ths). Step 4: verify by arpeggiating on guitar against recording. A wrong bass note makes any chord sound incorrect."},{"title":"Full Transcription","body":"Transcribe a complete piece: map form first, transcribe bass and chords, transcribe melody, transcribe signature lines, assemble lead sheet. Your first full transcription takes hours. Your hundredth takes minutes. This speed improvement reflects your ear becoming pattern-literate through practice."}],"tips":["Transcribe with voice before instrument; singing builds internal audiation for hearing music in your head","Write rhythms accurately from first listen; rhythmic notation is harder than pitches for most guitarists","Choose music you genuinely love; you will hear the same 4 bars hundreds of times"]}',
   null, null, 80, 50, true),

  ('a1c40000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000004',
   'Arrangement Principles',
   'Learn to arrange piano, orchestral, and ensemble works for solo guitar: voice allocation, texture management, and idiomatic writing.',
   5, 'theory',
   '{"intro":"Arranging for solo guitar is the art of reduction without loss of essence. A piano piece with ten voices or an orchestral score must be distilled to what is idiomatic on six strings. This lesson teaches what to keep, what to omit, and how to make the result sound guitaristic.","steps":[{"title":"Guitar Constraints and Possibilities","body":"Range: E2 (open 6th) to B5 (string 1 fret 19), about three and a half octaves. Maximum six simultaneous voices but practical polyphony rarely exceeds four. Guitar cannot sustain indefinitely; arrangements compensate through arpeggiation, tremolo, or re-articulation. Conversely, guitar offers capabilities no piano has: bending, glissando, vibrato on individual chord voices, and timbral variation via right-hand placement."},{"title":"Voice Allocation Priority","body":"Hierarchy: (1) Melody always preserved intact. (2) Bass, at minimum root on strong beats. (3) Characteristic countermelody or active inner voice. (4) Harmonic filler, least essential; chords thinned to 3rd and 7th guide tones without losing identity. A Bach four-voice chorale reduces naturally to three voices on guitar: soprano, bass, and most active inner voice."},{"title":"Three Textures","body":"Monophonic: single-line melody for introductions and interludes. Homophonic: melody with chordal accompaniment (default texture; melody on strings 1-2, bass on 5-6, chords on 3-4). Polyphonic: two or more independent melodic lines for fugal passages. Art lies in moving fluidly between textures within a single arrangement."},{"title":"Guitaristic Adaptation","body":"Close-voiced piano chords may be unplayable or muddy on guitar. Solutions: open voicing using drop-2 or drop-3 spacing; re-harmonize with guitaristic voicings preserving function; re-voice dense chords as arpeggiated figures. When arranging from orchestral scores, identify essential harmonic rhythm and reduce tutti passages to functional progression."}],"tips":["Begin with simple material (folk songs, hymn tunes) before complex piano works; principles identical but cognitive load lower","Study arrangements by Andres Segovia and Roland Dyens; analyze which voices they kept, omitted, and why","Play your arrangement for non-guitarist musicians; if they cannot identify the piece, you omitted something essential"]}',
   null, null, 0, 45, true);

-- ============================================================
-- CHAPTER 5: Extended Techniques & Sound Design
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, accuracy_threshold, estimated_minutes, is_premium) values

  ('a1c50000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000005',
   'Natural and Artificial Harmonics',
   'Unlock the ethereal bell-like tones of natural harmonics and full-range melodic capability of artificial harmonics.',
   1, 'exercise',
   '{"intro":"Harmonics are the overtone series made accessible on guitar. Natural harmonics at nodal points (frets 12, 7, 5, 4) and artificial harmonics on any fretted note transform the guitar into an instrument capable of ethereal, bell-like, synthesizer-like timbres.","steps":[{"title":"Natural Harmonic Nodes","body":"Harmonics occur where the string divides into equal segments. Fret 12: octave (halves). Fret 7: octave + fifth (thirds). Fret 5: two octaves (quarters). Fret 4: two octaves + major third (fifths). Touch the string lightly directly above the fret wire with the lightest possible touch, pluck with other hand, immediately remove touching finger. Never press to the fret."},{"title":"Artificial (Touch) Harmonics","body":"Left hand frets a note; right index touches the string exactly 12 frets above the fretted note while thumb (or pick) plucks behind the touch point. String 3 fret 5 (C), right index at fret 17. Resultant pitch is one octave above fretted note. This allows any melody played entirely in harmonics, signature of Lenny Breau, Ted Greene, and Tommy Emmanuel."},{"title":"Harmonic Chords and Cascades","body":"Play natural harmonics at fret 12 on all six strings sequentially for a cascading harp-like arpeggio used in film scores. Combine artificial harmonics: fret an Em chord, touch nodes 12 frets above each fretted note with right index, arpeggiate with thumb. Result: entire chord voiced in harmonics, crystalline choir-like sound."}],"tips":["Use bridge pickup or pluck near bridge for clearest natural harmonics; harmonics are rich in upper partials","Mark artificial harmonic touch points with stickers initially; touch points move with every fretted note","Practice right-index touch technique without pick first; isolate three-way coordination: left frets, right index touches, right thumb plucks"]}',
   null, null, 85, 50, true),

  ('a1c50000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000005',
   'Alternate Tunings Deep Dive',
   'Explore open tunings, dropped tunings, and modal tunings: their harmonic logic, unique chord shapes, and creative applications.',
   2, 'theory',
   '{"intro":"Alternate tunings are complete re-imaginings of guitar harmonic geography. When open strings form a chord, every fret becomes a potential new voicing. This lesson covers major tuning families, their harmonic implications, and the technique adjustments required.","steps":[{"title":"Open Major Tunings","body":"Open G (D G D G B D): Keith Richards signature; I IV V chords are one-finger barres at frets 0, 5, 7. Open D (D A D F# A D): I IV V at frets 0, 5, 7. Open E (E B E G# B E): same shape transposed up a whole step, Duane Allman and Derek Trucks slide tuning. In open tunings, the major scale is expressed as barre positions rather than note patterns."},{"title":"DADGAD: The Modal Tuning","body":"DADGAD (D A D G A D) is neither major nor minor; it is Dsus4 tuning (1-4-5, no 3rd), making it tonally ambiguous and extraordinarily flexible. Jimmy Page (Kashmir), Pierre Bensusan, and Celtic guitarists use it. Any fretboard position functions as major, minor, or suspended depending on fretted notes added. This tonal ambiguity is DADGAD primary creative asset."},{"title":"Harmonic Logic of Re-Tuning","body":"When open strings form a specific chord, every string-to-string interval changes. Every chord shape, scale pattern, and arpeggio must be relearned. However, underlying music theory does not change: C is still C. Approach each tuning as a new instrument. Map open string pitches, identify octave positions, construct fingerings from first principles. Do not import standard-tuning shapes."},{"title":"Practical Tuning Transitions","body":"Tuning up (tightening) is safer than tuning down. Open D and DADGAD share three strings at identical pitch (D A D), enabling quick switching. Dropped D (DADGBE) is the gentlest introduction: only string 6 changes, while all standard chord shapes on strings 1-5 remain unchanged."}],"tips":["Spend first 30 minutes in new tuning playing only open strings; let ear acclimate before adding fretted notes","Learn one complete song in new tuning before improvising; repertoire is fastest path to internalizing tuning geometry","Label string sets if keeping multiple guitars in different tunings; returning to DADGAD after a week requires recalibration"]}',
   null, null, 0, 40, true),

  ('a1c50000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000005',
   'Slide Guitar Technique',
   'Develop the vocal, crying tone of bottleneck slide: intonation, vibrato, damping, and phrasing in open tunings.',
   3, 'exercise',
   '{"intro":"Slide guitar is the closest the instrument comes to the human voice. Continuous pitch gliding, impossible with fretted notes, creates the vocal quality defining Delta blues and Southern rock. This lesson covers left-hand slide technique, right-hand muting, and essential slide vocabulary.","steps":[{"title":"Slide Selection and Setup","body":"Materials: glass (warm, smooth, Duane Allman), brass (bright, cutting, Billy Gibbons), chrome steel (loudest sustain, Lowell George), ceramic (midrange, Sonny Landreth). Fit snug on ring or pinky. Raise action to 2.5-3mm at fret 12; slide must glide above frets without contacting them. Consider heavier strings (12-56) for dedicated slide guitar."},{"title":"Slide Intonation","body":"Slide pitch is 100% ear-dependent. Position slide directly above fret wire (not between frets). Verify: play open string, then slide to fret 12; two pitches must match perfectly in unison. Use tuner for visual feedback. Practice unisons: slide on string 2 to match open string 1; beating between pitches disappears at perfect unison."},{"title":"Right-Hand Damping","body":"Damping is as important as the slide. Picking-hand palm mutes lower strings near bridge. Fretting-hand fingers behind the slide damp upper strings. Slide finger touches only the target string. Practice: single note on string 1 with absolutely zero sound from strings 2-6. Then double-stops muting strings 3-6."},{"title":"Slide Vibrato","body":"Oscillate slide slightly above AND below target pitch; movement from wrist, not fingers. Wide/slow: emotional gospel (Duane Allman). Narrow/fast: urgent intense (Johnny Winter). Most common error: going sharp and never returning flat, sounding out of tune. Practice equal oscillation both ways."}],"tips":["Practice in open E or D initially; any straight barre across all strings produces a chord, forgiving while developing intonation","Mimic vocalists with the slide; Aretha Franklin scoops and falls translate directly in ways fretted notes cannot match","Record slide playing and listen for metallic zinging of slide hitting frets; indicates action too low or pressure too heavy"]}',
   null, null, 85, 55, true),

  ('a1c50000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000005',
   'Effects and Signal Chain',
   'Understand every pedal category and signal-chain principle: gain staging, order effects, and crafting your signature sound.',
   4, 'theory',
   '{"intro":"Effects are not an afterthought; they are part of the instrument. Understanding how each effect category functions, how signal chain order changes results, and how to combine effects tastefully transforms you from a guitarist who owns pedals into one who sculpts sound intentionally.","steps":[{"title":"Gain Staging","body":"Signal path: compressor first (evens dynamics before drives), then drives in increasing gain order (overdrive to distortion to fuzz). Stacking: low-gain overdrive (gain 9:00, volume 3:00) into moderate distortion produces tighter, more articulate lead tone than either alone. Overdrive tightens low end and adds midrange presence. Active pickups interact differently with vintage fuzz pedals than passive pickups."},{"title":"Modulation Effects","body":"Chorus: slightly delayed (20-40ms) pitch-modulated copy, creates illusion of multiple guitars. Flanger: shorter delay (1-15ms) with feedback, jet-plane swoosh. Phaser: all-pass filters creating sweeping frequency notches. Standard placement: modulation after drives, before delay/reverb. Alternative: phaser before distortion creates dramatically more aggressive sweep."},{"title":"Delay and Reverb","body":"Delay types: analog (warm, dark, decaying repeats), tape (saturation, wow/flutter), digital (pristine, tap tempo). Dotted 8th note delay creates the U2/Edge galloping rhythmic echo. Reverb types: spring (bright splashy Fender), plate (smooth dense studio), hall (large cinematic), room (subtle natural). Wash technique: high mix, moderate decay, sparse playing."},{"title":"Creative Signal Chain Design","body":"Conventional: tuner to compressor to drives to modulation to delay to reverb to amp. Alternatives: reverb BEFORE distortion (distortion clips reverb tail, massive wall of sound, shoegaze/My Bloody Valentine). Delay before distortion: each repeat progressively cleaner. Tremolo after reverb: entire ambient wash pulses. No absolute rules, only consequences. Understand each ordering consequence and choose intentionally."}],"tips":["Set effect parameters with full band mix in mind; reverb beautiful alone can bury guitar in a band context","Name and save presets by song and section (Lonely Boy Verse); this prevents forgetting which setting belongs where","Test signal chain at performance volume; Fletcher-Munson curve means frequency balance changes dramatically between bedroom and stage"]}',
   null, null, 0, 40, true),

  ('a1c50000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000005',
   'Tapping and Two-Hand Techniques',
   'Master eight-finger tapping, pioneered by Eddie Van Halen and evolved by Stanley Jordan, Tosin Abasi, and Yvette Young.',
   5, 'exercise',
   '{"intro":"Two-hand tapping transforms the guitar into a touchboard instrument. From Eruption to Stanley Jordan pianistic counterpoint to Animals as Leaders polyrhythmic djent, tapping has evolved into a primary technique across virtually every modern genre.","steps":[{"title":"Basic Right-Hand Tapping","body":"Right-hand index (or middle) hammers onto fretboard with same motion as left-hand hammer-on: velocity, not force. Pattern: left hand frets string 2 fret 5 (E), right hand taps string 2 fret 12 (B), then pull off sideways to reveal fretted E. Tapped note must ring clearly without picking. Pull-off after tap is a plucking motion; tapping finger flicks sideways as it releases."},{"title":"Multi-Finger Tapping Arpeggios","body":"Left hand anchors root (string 6 fret 5 = A). Right hand taps arpeggio: index taps string 3 fret 9 (E), middle taps string 2 fret 10 (A), ring taps string 1 fret 12 (E). Creates arpeggiated textures impossible with pick. Stanley Jordan uses all five right-hand fingers independently, each on a specific string, playing genuine counterpoint."},{"title":"Tapped Harmonics","body":"Tap exactly 12 frets above a fretted note for an artificial harmonic. Left hand string 3 fret 5 (C); right taps fret 17; harmonic rings at octave. Combine tapped harmonics with standard taps for multi-octave arpeggios with ethereal upper registers. Tosin Abasi uses this extensively for shimmering high end above low-tuned riffs."},{"title":"Symmetrical Two-Hand Tapping","body":"Left and right hands mirror each other: left ascends while right descends in contrary motion, creating lines sounding like two independent players. Start: left plays string 5 frets 5-7-8 while right taps string 2 frets 12-10-8. Hands move in opposite directions, creating expanding and contracting intervals unique to guitar."}],"tips":["Tap with fingertip pad, not extreme tip; more surface area means more consistent contact and clearer tone","Muting even more critical with tapping; use fretwrap at nut and keep both palms touching unused strings","Set action as low as possible for tapping; high action requires excessive force, slowing speed and reducing accuracy"]}',
   null, null, 85, 55, true);

-- ============================================================
-- CHAPTER 6: Composition & Songwriting
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, accuracy_threshold, estimated_minutes, is_premium) values

  ('a1c60000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000006',
   'Melody Writing',
   'Compose compelling, singable melodies using motivic development, contour, tension-resolution, and melody-harmony relationship.',
   1, 'theory',
   '{"intro":"A great melody feels inevitable yet surprising; each note seems the only possible choice yet could not have been predicted. Melody writing follows principles that can be studied, practiced, and internalized. This lesson breaks down the architecture of memorable melody: contour, rhythm, interval choice, and the critical melody-harmony relationship.","steps":[{"title":"Contour and Shape","body":"Every melody has a visual contour. Most effective melodies feature: a central reciting tone (often the 5th or 3rd), stepwise motion for singability, one or two strategic leaps for drama, and a single climax pitch occurring once, roughly two-thirds through the phrase. Sketch contour as a line drawing before choosing specific pitches; the shape comes first."},{"title":"Motivic Structure","body":"Most timeless melodies are built from a single small motif (2-5 notes) repeated, varied, and developed. Verse motif and chorus motif should contrast: verse rhythmically active (eighth notes, narrow range), chorus rhythmically broader (longer notes, higher register, wider intervals). This contrast creates the energy shift making a chorus feel like a release."},{"title":"Melody-Harmony Relationship","body":"Melody notes are either chord tones (1,3,5,7 of chord: stable, consonant) or non-chord tones (everything else: tense, seeking resolution). Aim for 60-70% chord tones on strong beats and 30-40% non-chord tones on weak beats. The melodic engine runs on this tension-release cycle: non-chord tone creates tension resolving by step to chord tone."},{"title":"Guitar-Specific Melody","body":"Compose melodies exploiting guitar unique capabilities: bends (microtonal inflection), slides (continuous pitch connection), hammer-ons/pull-offs (legato at speed), open-string drones. Include a pre-bend release, a slide between chord tones, and an open string ringing as a pedal beneath a moving line. The melody should feel conceived on guitar."}],"tips":["Sing every melody you write; if you cannot sing it expressively, listeners will not remember it","Compose 10 melodies for every 1 kept; first five are cliches, next four experiments, tenth may be original","Study melodies outside your genre; Joni Mitchell teaches differently than John Mayer, and both differently than Chopin"]}',
   null, null, 0, 40, true),

  ('a1c60000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000006',
   'Harmonic Structure and Form',
   'Master song form: verse, chorus, bridge, pre-chorus, and the harmonic architecture giving each section its function.',
   2, 'theory',
   '{"intro":"Song form is harmonic architecture at scale. The difference between good and great songs is often structural: where chords go, how sections relate, and how tension distributes across time. This lesson codifies harmonic principles of each formal section.","steps":[{"title":"The Verse: Harmonic Stasis","body":"The verse is the narrative engine; its harmonic goal is establishing the key without definitively resolving to it. The four-chord loop (I-V-vi-IV cycling) creates hypnotic stasis; progression never feels finished, so chorus arrival is deeply welcome. Verse should end on dominant or subdominant, not tonic, propelling the listener forward."},{"title":"The Chorus: Harmonic Arrival","body":"The chorus provides the resolution the verse withholds. It typically begins on I (immediate arrival) and contains the song most definitive cadence. Chorus harmony should be simpler and more repetitive than verse: fewer chords, longer harmonic rhythm. Classic minor verse/major chorus archetype (verse Am, chorus C) creates lift through modulation; heard in Hotel California and Stairway to Heaven."},{"title":"Pre-Chorus and Bridge","body":"Pre-chorus (2-4 bars): transitional, moving to dominant, building harmonic tension released by chorus. Bridge: departure section starting on non-tonic (typically IV or vi), providing break before final return. Bridge is where you introduce most adventurous harmony: borrowed chords, modulation, unusual progression."},{"title":"Complete Song Architecture","body":"Map tension on timeline: Verse 1 (low) to Pre-chorus (rising) to Chorus 1 (release) to Verse 2 (slightly higher with variation) to Pre-chorus 2 (intensified) to Chorus 2 (higher energy) to Bridge (maximum tension, departure) to Final Chorus (definitive resolution). This arc powers thousands of classic songs from The Beatles to Taylor Swift."}],"tips":["Analyze harmonic structure of 10 favorite songs; map each section chord progression and identify its harmonic function","When stuck, force a structural decision: modulate to relative minor for verse or end chorus on deceptive cadence (V-vi)","Block out structure in DAW before writing chords; placing blank sections clarifies container before filling with content"]}',
   null, null, 0, 40, true),

  ('a1c60000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000006',
   'Lyric Setting and Prosody',
   'Set words to music with natural speech rhythm: principles of prosody, scansion, and the marriage of lyric and melody.',
   3, 'theory',
   '{"intro":"Prosody is the alignment of musical stress with linguistic stress. When music agrees with words, the song feels natural and powerful. When they disagree, the song feels awkward regardless of individual quality. This lesson teaches the craft of fitting words to music as a songwriter-guitarist.","steps":[{"title":"Scansion: Mapping Speech to Rhythm","body":"Mark stressed (/) and unstressed (u) syllables. ''Melody'' is MEL-o-dy, stress on first syllable. Setting it as mel-O-dy sounds wrong. In 4/4, beats 1 and 3 are strong, 2 and 4 are weak. Stressed syllables and important words on strong beats; unstressed syllables and function words (the, and, of) on weak beats or offbeats. Scan lyrics before setting them."},{"title":"Melodic Prosody","body":"Pitch should reflect meaning. Rising melody for questions (Will you still love me?), falling for statements. High pitch for intensity, low for intimacy. Large intervals on dramatic words (leaps on cry, fly, sky), stepwise motion for conversational passages. These are tendencies audiences perceive unconsciously; breaking them intentionally creates irony or unease."},{"title":"Lyric Density","body":"Sparse lyrics (2-4 syllables/bar) create space and weight; each word looms large (Leonard Cohen Hallelujah). Dense lyrics (8-16 syllables/bar) create energy and momentum (Bob Dylan). Vary density: verse=denser (storytelling), chorus=sparser (hook). Packed verse followed by sparse chorus with held notes creates satisfying contrast."},{"title":"Rhyme and Sonic Texture","body":"Rhyme scheme provides structural expectation. Perfect rhyme (moon/June): strongest closure. Near-rhyme (moon/room): subtler. Internal rhyme: propulsion. Assonance (repeated vowels) and consonance (repeated consonants) provide sonic texture. Plosive consonants (p,t,k,b,d,g) are percussive on rhythmic parts; open vowels (ah,oh,ee) sustain on held notes."}],"tips":["Speak lyrics aloud unaccompanied with exaggerated natural rhythm; let speech rhythm suggest melody rhythm","When lyric and melody conflict, revise lyric first; music is harder to change and more likely what listeners remember","Read formal poetry (sonnets, villanelles) to internalize meter and rhyme; poets have solved prosodic problems for centuries"]}',
   null, null, 0, 40, true),

  ('a1c60000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000006',
   'Arranging for Solo Guitar',
   'Create self-contained solo guitar arrangements combining melody, bass, and harmony: chord-melody for your compositions.',
   4, 'exercise',
   '{"intro":"A solo guitar arrangement must do the work of an ensemble on six strings. This is chord-melody: melody harmonized with chords implying bass movement. This lesson guides you through arranging your compositions for unaccompanied guitar.","steps":[{"title":"Map Melody on Strings 1-2","body":"Place melody on top two strings where it projects clearest and leaves space for bass and chords. Transpose so highest note is at or below fret 15 on string 1, lowest no lower than open string 2. Play entire melody as single-note line first, memorizing completely. Every subsequent decision depends on knowing where every melody note falls."},{"title":"Harmonize the Melody","body":"For each melody note, ask: what chord(s) contain this note as a chord tone? If E is in melody and harmony is C major, E is the 3rd; any C voicing with E on top works. Strategy: harmonize strong-beat melody notes with full chords; let weak-beat notes pass as single notes or double-stops. Alternating texture is more musical than constant block chords."},{"title":"Add the Bass Line","body":"Bass on beats 1 and 3, chords on 2 and 4 (Charleston rhythm). Bass should move contrary or oblique to melody for independent voice leading. Use chromatic approaches: for C to Am, walk bass C-B-A (chromatic descent) rather than leaping. This inner voice activity elevates arrangement from functional to artful."},{"title":"Assemble Complete Arrangement","body":"Section A (8 bars): state melody clearly over simple bass-chord accompaniment. A repeated: richer voicings, more active bass. B (bridge): different texture, arpeggiated or single-note. A final: fullest arrangement, most active bass, climactic peak, quiet ending. Record and check: melody must ALWAYS be the loudest voice. If chords overpower melody, thin the voicing or play chords softer."}],"tips":["Write arrangement in notation or tablature; writing forces precision; what sounds passable improvised may not survive scrutiny","Record bass and chords without melody, then play melody over the recording to test polyphonic integrity","Study Joe Pass chord-melody recordings; Summertime and Autumn Leaves are masterclasses in three-element balance"]}',
   null, null, 80, 55, true),

  ('a1c60000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000006',
   'Recording and Producing Demos',
   'Produce professional-quality guitar demos at home: microphone techniques, DI recording, multi-tracking, and mixing.',
   5, 'theory',
   '{"intro":"The ability to record yourself well is as essential as playing well. Whether capturing ideas, producing demos, or releasing tracks, understanding the recording chain ensures your guitar sounds as compelling recorded as in the room.","steps":[{"title":"Microphone Techniques for Acoustic","body":"Small-diaphragm condenser at 12th fret, 6-12 inches from guitar, captures both string articulation and body resonance. Closer than 6 inches: proximity effect boosts bass, useful for fingerstyle, problematic for strumming. Two-mic stereo: XY coincident pair (capsules aligned at 90 degrees) for phase-coherent stereo; spaced pair (bridge + 12th fret, 18+ inches apart) for wider image. Always check mono compatibility."},{"title":"DI Recording and Amp Simulation","body":"Guitar into Hi-Z instrument input; standard line inputs load passive pickups incorrectly causing treble loss. Raw DI feeds amp sims (Neural DSP, Amplitube, Helix Native, Tonex). Cabinet impulse response (IR) is the single most important tonal component; stock cab sims are often the weak link. Third-party IRs (OwnHammer, York Audio) dramatically improve realism."},{"title":"Multi-Tracking and Layering","body":"Double-tracking: record same part twice (separate performances, NOT copy-paste), pan hard left/right. Subtle timing and pitch differences create massive stereo width. Quad-tracking (metal): four performances, two per side with slightly different amp settings. Acoustic layering: one mic (warmth), one piezo DI (brightness), blended to taste."},{"title":"Mixing Guitar in a DAW","body":"EQ: high-pass at 80-120 Hz to remove rumble competing with bass and kick. Cut 200-400 Hz if muddy. Boost 2-5 kHz for presence. Compression: 3:1 to 4:1 ratio, fast attack (5-10ms), medium release (50-100ms). Reverb and delay on sends (aux channels), not inserts. 20-40ms pre-delay on reverb separates dry signal from reverb tail."}],"tips":["Record practice sessions even with smartphone; recording never lies about timing inconsistencies or uneven dynamics","Compare mix against professional reference track; match EQ, perceived loudness, spatial placement, and dynamic range","Invest in monitoring before more gear; you cannot fix what you cannot accurately hear"]}',
   null, null, 0, 45, true);

-- ============================================================
-- CHAPTER 7: Genre Mastery
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, accuracy_threshold, estimated_minutes, is_premium) values

  ('a1c70000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000007',
   'Advanced Rock and Metal Techniques',
   'Master palm muting precision, tremolo picking, pinch harmonics, dive bombs, and riff architecture.',
   1, 'exercise',
   '{"intro":"Rock and metal guitar technique has evolved into a specialized vocabulary: palm-muted chugging at 200+ bpm, squealing pinch harmonics, whammy bar acrobatics, and multi-layered riff construction. This lesson distills the essential techniques underpinning modern rock and metal guitar.","steps":[{"title":"Palm Muting Precision","body":"Rest picking-hand palm edge lightly on strings, 1-2cm from bridge saddles. Sweet spot produces percussive chug with clear pitch but short aggressive sustain. Practice palm-muted open E at 120 bpm in steady eighth notes. Vary pressure within riff: lighter=more ring, heavier=more percussion. The dynamic movement between muted and open notes creates metal rhythm push-pull energy."},{"title":"Tremolo Picking Endurance","body":"Rapid alternate picking on single string: string 6 open at 100 bpm sixteenth notes. Pick tip must move no more than 2-3mm past string in either direction. Larger motion wastes energy and limits maximum speed. Wrist drives motion, not forearm or elbow. Increase 5 bpm only when sustaining perfect sixteenths for 60 seconds without tension or deterioration."},{"title":"Pinch Harmonics","body":"Pinch harmonic: picking thumb lightly contacts string immediately after pick strikes it. Contact point determines harmonic pitch: near bridge=high squeal, farther=lower harmonic. Experiment thumb position between pickups and bridge. Mark 3-4 sweet spots with tape dots. Dimebag Darrell and Zakk Wylde are canonical masters."},{"title":"Riff Architecture","body":"A great metal riff is a self-contained composition with rhythmic motif, harmonic identity, and internal dynamic contrast. Enter Sandman alternates single-note pedal (E) and power chord (E5), creating thin-to-thick textural contrast. The rhythmic hook (dotted eighth+sixteenth+eighth) is as important as the notes. Compose riffs by first establishing rhythmic cell, then assigning pitches."}],"tips":["Practice palm muting with metronome at various subdivisions; tight vs. sloppy metal is sub-millisecond difference","Mark pinch harmonic sweet spots with tape at specific frets; they shift position for every fretted note","Use noise gate in high-gain chain; gate closes between notes eliminating hiss that reduces percussive impact"]}',
   null, null, 85, 50, true),

  ('a1c70000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000007',
   'Country Guitar Chicken Pickin and Hybrid Picking',
   'Master Telecaster twang: chicken pickin, hybrid picking, double stops, pedal steel bends, and classic country vocabulary.',
   2, 'exercise',
   '{"intro":"Country guitar is defined by articulation: the crisp snap of hybrid picking, the percussive pop of chicken pickin, the crying bends mimicking pedal steel. These techniques, pioneered by James Burton, Albert Lee, and Brent Mason, combine fingerstyle precision with plectrum attack.","steps":[{"title":"Hybrid Picking Fundamentals","body":"Flatpick (thumb+index) handles lower strings; middle (m) and ring (a) fingers pluck higher strings. Exercise: pick string 3 open with flatpick, simultaneously pluck string 1 open with ring finger; both must sound at exactly the same moment with equal volume. Alternate: pick string 4, pluck string 2 (middle), pick string 3, pluck string 1 (ring) for a rolling piano-like arpeggio."},{"title":"Chicken Pickin: The Muted Pop","body":"Pick a note, then immediately relax fretting finger so string mutes against it; a short percussive cluck with definite pitch but almost no sustain. Combine with open-string notes: pick muted C on string 3, then immediately pluck open G (string 3). The contrast between dead percussive note and ringing open string IS chicken pickin. Brent Mason and Johnny Hiland are modern masters."},{"title":"Double Stops and Pedal Steel Bends","body":"Country lead is built on double stops: two notes, typically third, fourth, or sixth apart. Over G: play B (string 2 fret 12) and G (string 1 fret 15). Move shapes through I-IV-V. Pedal steel bends: bend one note of a double stop while holding the other steady; the moving voice against static voice creates the liquid vocal pedal steel quality."},{"title":"Open-String Cascades and Banjo Rolls","body":"Country exploits open strings in friendly keys (G, D, A, E). The G run cascading lick: open string 3 (G), string 2 fret 1 (C), open string 2 (B), open string 1 (e), string 2 fret 3 (D), string 1 fret 3 (G). Banjo rolls: thumb-index-middle (T-I-M) forward roll on strings 4-3-2 while melody plays on strings 1-2. Two independent layers from one hand."}],"tips":["Set up for country: lighter strings (9-42), action moderately low, bridge pickup for maximum twang","Record I-IV-V country backing track and practice all techniques over it; context is everything","Listen to Brent Mason and Albert Lee recordings; transcribe 4 bars of their hybrid-picked lines"]}',
   null, null, 80, 50, true),

  ('a1c70000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000007',
   'Funk and R and B Groove',
   'Develop tight, percussive 16th-note strumming, ghost notes, and the rhythmic vocabulary of funk and R&B guitar.',
   3, 'exercise',
   '{"intro":"Funk guitar is a rhythm-section instrument first and foremost. The left hand mutes and chokes; the right hand locks into 16th-note subdivisions with metronomic precision. This lesson develops the scratch, the chuck, and the tight rhythmic pocket of Nile Rodgers, Cory Wong, and Prince.","steps":[{"title":"The 16th-Note Scratch","body":"Left hand mutes all six strings by lightly touching without pressing to frets. Right hand strums steady 16th-note pattern: D-U-D-U-D-U-D-U in continuous motion; the pick never stops moving. Accent specific subdivisions: beat 1, and of beat 2, beat 3, a of beat 4. The strumming arm is a metronome; the scratch is purely percussive and rhythmic."},{"title":"Single-Note Funk Lines","body":"Play single notes on lower strings with sharp staccato articulation. Fretting hand releases pressure immediately after each note to choke sustain. String 6 frets 5-7 (A-B) with dead choked articulation creates bass-like funk line. Layer with scratch pattern: scratch on beats 1-2, choked single notes on beats 3-4. Contrast between percussive scratch and pitched stabs creates funk texture."},{"title":"The Chuck: Muted Chord Stabs","body":"Fret a chord shape (E9: x7676x) but press just enough for pitch, not full pressure. Strum aggressively on the and of beats 2 and 4. Result: pitched percussive stab with minimal sustain. Nile Rodgers uses this on every Chic recording. The chuck is the backbone of funk rhythm guitar; pitch content matters less than rhythmic precision."},{"title":"Wah-Wah as Rhythmic Filter","body":"Wah pedal used as rhythmic filter, not solo effect. Rock pedal in sync with strumming: toe down (treble) on downbeats, heel down (bass) on upbeats. Creates sweeping vocal quality making simple chord vamps sound dynamic and alive. Practice 16th-note scratch while rocking wah in quarter-note pulses, then eighth-note pulses."}],"tips":["Practice funk rhythms with drummer or drum machine; guitar alone sounds sparse; funk guitar only makes sense locked into rhythm section","Use compressor with fast attack to even volume between scratches, chucks, and single notes; consistency is funk secret weapon","Listen to James Brown guitarists (Jimmy Nolen, Catfish Collins); single-chord vamps are masterclasses in rhythmic variation"]}',
   null, null, 75, 50, true),

  ('a1c70000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000007',
   'Blues-Rock Fusion',
   'Bridge traditional blues vocabulary and modern rock aggression, combining pentatonic fluency with advanced harmony and technique.',
   4, 'exercise',
   '{"intro":"Blues-rock fusion takes blues vocabulary (pentatonics, bends, vibrato, call-and-response) through rock technique: higher gain, faster tempos, wider vibrato, and harmonic expansion beyond I-IV-V. This is the style of Joe Bonamassa, Philip Sayce, and Eric Gales.","steps":[{"title":"The Expanded Blues Scale","body":"Combine minor pentatonic (A C D E G) with major pentatonic (A B C# E F#) into hybrid blues scale. Over A7, alternate between minor 3rd (C) and major 3rd (C#); this microtonal ambiguity IS the blues. At position 5: bend string 3 fret 5 (C) up a quarter-step toward C#. This blue note bend landing between minor and major is the defining blues sonority."},{"title":"Fast Blues-Rock Legato Lines","body":"Combine pentatonic positions with legato for signature modern blues-rock sound. A minor pentatonic position 5: string 3 frets 5-7, string 2 frets 5-8, string 1 frets 5-8. Play entire line with one pick stroke per string, hammering remaining notes. Creates fluid horn-like phrasing of Joe Bonamassa. Speed up gradually; vocal fluidity is goal, not mechanical speed."},{"title":"Chord Stabs and Dynamic Contrast","body":"Aggressive chord stabs between lead phrases. Over slow blues in A: lead phrase, then stab A7#9 (Hendrix chord: x0768x) as punctuation. Then another lead phrase, then lower-register response. This call-and-response between single-note lines and chordal punctuation is the structural foundation of blues-rock vocabulary."},{"title":"Harmonic Expansion Beyond I-IV-V","body":"Inject jazz-blues harmony: add ii-V-I cadences between blues changes, use 7#9 and 13th chords instead of plain 7ths, insert diminished passing chords. A 12-bar blues in A becomes: A13 to D9 to A13 to Em7-A7b9 to D9 to D#dim7 to A13 to F#7#9 to Bm7-E7#9 to A7-D7. Blues vocabulary remains; harmonic canvas is vastly richer."}],"tips":["Practice minor-to-major 3rd bend slowly; the quarter-tone inflection between them is the most expressive blues-rock note","Study Joe Bonamassa live solos; his combination of traditional blues phrasing with modern legato and expanded harmony defines the style","Record 12-bar blues with jazz-blues harmony and force yourself to target chord tones you normally avoid, like 9ths and 13ths"]}',
   null, null, 80, 50, true),

  ('a1c70000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000007',
   'Progressive and Experimental Styles',
   'Explore odd time signatures, polyrhythms, atonality, extended techniques, and the progressive compositional mindset.',
   5, 'theory',
   '{"intro":"Progressive and experimental guitar pushes beyond conventional tonality, rhythm, and technique. Odd time signatures, polyrhythms, non-functional harmony, prepared guitar, and extended performance practices define this territory: King Crimson, Tool, Sonic Youth, Stian Westerhus.","steps":[{"title":"Odd Time Signatures","body":"Beyond 4/4: practice riff construction in 5/4, 7/8, 9/8, 11/8. Count odd meters by grouping beats: 7/8 = 1-2-1-2-1-2-3 or 1-2-3-1-2-1-2. The grouping determines the groove. Compose a riff in 7/8 in two different groupings; same notes with different accent patterns feel like completely different riffs."},{"title":"Polyrhythms and Polymeters","body":"Polyrhythm: two subdivisions simultaneously. Guitarist plays 3/4 pattern while drummer maintains 4/4; every 12 beats patterns realign. Polymeter: two time signatures simultaneously. Compose guitar part in 5/8 over drums in 4/4; meters cycle independently creating shifting accent relationships. Tool and Meshuggah are canonical references."},{"title":"Non-Functional and Atonal Harmony","body":"Non-functional harmony uses progressions not driven by dominant-tonic resolution. Planing: move identical chord shape in parallel (Cmaj7-Dmaj7-Emaj7, all major 7ths). Quartal harmony: chords built in fourths rather than thirds (E-A-D-G-C, stacked perfect fourths, the So What chord). Atonal composition abandons key centers; each note chosen for sonic color rather than function."},{"title":"Extended and Prepared Techniques","body":"Prepared guitar: insert objects between strings (screws, alligator clips, paper) altering timbre (Fred Frith, Keith Rowe). Ebow and sustainer: electromagnetic infinite sustain. Playing behind nut or bridge, bowing strings with violin bow, percussive body tapping expand sonic vocabulary beyond traditional pitched notes into pure texture and timbre."}],"tips":["Internalize odd meters by walking in them; physically stepping to 5/4 or 7/8 embeds the meter in your body","Compose one complete piece in an odd meter before attempting polyrhythms; master one non-standard meter deeply first","Listen to King Crimson (Discipline), Tool (Lateralus), and Steve Reich (Electric Counterpoint) for foundational vocabulary"]}',
   null, null, 0, 45, true);

-- ============================================================
-- CHAPTER 8: Performance & Interpretation
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, accuracy_threshold, estimated_minutes, is_premium) values

  ('a1c80000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000008',
   'Stage Presence and Performance Psychology',
   'Master performance anxiety management, stage movement, audience connection, and mental preparation.',
   1, 'theory',
   '{"intro":"Technical mastery means nothing if it cannot be delivered under pressure. Stage presence and performance psychology are skills as trainable as scales. This lesson covers pre-performance preparation, managing adrenaline, graceful mistake recovery, and authentic audience connection.","steps":[{"title":"Pre-Performance Preparation","body":"Mental rehearsal: visualize the entire performance (walking onstage, first chord, solo, applause). Sports psychology shows visualization activates the same neural pathways as physical practice. Arrive early, check gear thoroughly, warm up at least 20 minutes including your hardest passages. Establish a consistent pre-show ritual; ritual signals to your brain that it is performance time."},{"title":"Managing Performance Anxiety","body":"Adrenaline is not the enemy; it is your ally if channeled correctly. Physical symptoms (racing heart, sweaty hands, shallow breathing) are physiologically identical to excitement. Reframe: I am not nervous; I am excited and prepared. Box breathing: inhale 4, hold 4, exhale 4, hold 4, repeat 4 times. This activates the parasympathetic nervous system."},{"title":"Stage Movement and Body Language","body":"Your body communicates before a single note sounds. Walk onstage with confidence: shoulders back, head up, acknowledging the audience. Movement should serve the music, not distract. Rock players move freely; classical players communicate through posture and expression. Universal principle: physical energy must match musical emotional energy."},{"title":"Mistake Recovery","body":"Mistakes happen to every performer. The skill is recovery: never stop, never apologize mid-performance, never make a face signaling you messed up. 99% of audience will not notice a wrong note if you continue with confidence. If lost, find beat 1 of next measure and re-enter decisively. The audience experience is defined by recovery, not the mistake."}],"tips":["Record practice run-throughs as if performances; the red recording light creates performance-level adrenaline weekly","Perform for one person before fifty; the gradual progression builds confidence incrementally","Watch live performances of favorite artists; study what they do between songs where audience connection is built or lost"]}',
   null, null, 0, 40, true),

  ('a1c80000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000008',
   'Ensemble Playing',
   'Learn to listen, blend, and interact in a group setting: the skills distinguishing a band member from a soloist playing alongside.',
   2, 'theory',
   '{"intro":"Playing with other musicians is a distinct skill from playing alone. It requires active listening, dynamic sensitivity, rhythmic lock, and the humility to serve the music rather than your ego. This lesson covers essential ensemble musicianship for guitarists in any genre.","steps":[{"title":"Active Listening","body":"In an ensemble, you must hear everything simultaneously while playing. Practice: record yourself playing rhythm to a metronome, then play lead over it, listening critically to the recorded part. Expand: record bass and drums, add guitar; listen to how your part fits. The goal: monitoring four or more musical lines simultaneously while contributing your own."},{"title":"Dynamic Sensitivity and Blend","body":"Guitarist default volume is often too loud. In an ensemble, volume must match the musical moment. During verses (vocal present): play quieter, thinner voicings, less low end. During your solos: increase volume and presence. During others solos: drop volume significantly, simplify your part. The volume knob and pickup selector are expressive tools; use them continuously."},{"title":"Rhythmic Lock with Bass and Drums","body":"The rhythm section is the band engine. You either reinforce the groove (rhythm playing) or float over it (lead). When comping, lock with the snare drum (beats 2 and 4) and bass player note placement. The pocket, that precise rhythmic placement making a band feel tight, lives in the milliseconds between kick, snare, and your guitar."},{"title":"Arrangement Roles","body":"In multi-guitar bands, define roles clearly. Guitar 1: primary rhythm and foundation. Guitar 2: complementary parts in different register or texture (capo, alternate voicing, arpeggiated). Avoid playing identical parts in same register; this creates mud, not power. One guitarist plays open chords while other plays barre chords higher up; different voicings of the same harmony."}],"tips":["Record band rehearsals and listen critically to your part in isolation; are you playing too much? Too loud?","Learn every other instrument part in at least one song; understanding what others play transforms how you approach your part","Make eye contact with bandmates at key moments; a head nod for tempo change or dynamic shift is irreplaceable visual communication"]}',
   null, null, 0, 40, true),

  ('a1c80000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000008',
   'Sight-Reading and Chart Interpretation',
   'Develop real-time chart reading: lead sheets, Nashville numbers, slash notation; the skill making you hireable.',
   3, 'exercise',
   '{"intro":"Professional guitarists read and interpret charts on the spot at sessions and gigs where there is no time to learn material in advance. Sight-reading charts is distinct from reading fully notated music. This lesson covers lead sheets, Nashville numbers, slash notation, and real-world chart interpretation.","steps":[{"title":"Lead Sheet Reading","body":"A lead sheet provides melody (standard notation), chord symbols, and lyrics. Your job: comp appropriate voicings and optionally play melody as chord-melody. Practice: take Real Book lead sheet (Autumn Leaves, All of Me) and comp through at tempo reading only chord symbols using drop-2 or shell voicings. No rehearsal; first read is first play."},{"title":"Nashville Number System","body":"Scale-degree numbers replace chord names. In key of C: 1=C, 4=F, 5=G, 6m=Am. Chart reads: 1 4 1 5 / 1 4 6m 5. Leader says Blues in G; you transpose numbers to G on the fly: G C G D / G C Em D. One chart works in any key. Practice transposing I-IV-V-I and I-V-vi-IV to all 12 keys using Nashville numbers as mental framework."},{"title":"Slash Notation and Rhythm Charts","body":"Rhythm charts: four slashes per bar indicate time, chord symbols above indicate harmony, specific rhythmic hits notated when needed. Your job: create appropriate comping pattern fitting the style. Chart says Funk 100 bpm Bb7 with four slashes; you invent a funk-appropriate 16th-note strumming pattern. This requires stylistic vocabulary across genres."},{"title":"Reading in Professional Settings","body":"In sessions, you often see a chart for the first time moments before the downbeat. Strategy: scan form first (repeats, codas, DS al Coda), identify unusual chords or time changes, note key and style, establish default comping pattern before count-in. Play simply and accurately on first pass; complexity can come later. A guitarist playing simple parts perfectly on first read is more hireable than one attempting complex parts with errors."}],"tips":["Practice reading charts you have never seen before; use random Real Book pages or online lead sheet generator","Learn Nashville number system fluently in all 12 keys; instant transposition makes you invaluable in sessions","Record first-read attempts and critique honestly; professional sight-reading means the first read IS the performance"]}',
   null, null, 75, 50, true),

  ('a1c80000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000008',
   'Studio Recording Technique',
   'Adapt your playing for the recording studio: consistency, tone choices, playing to the grid, and psychological demands.',
   4, 'theory',
   '{"intro":"Recording is a different discipline from live performance. The studio magnifies every detail: every string squeak, slightly rushed note, imperfect mute. This lesson covers the technical and psychological adjustments required for professional recorded performances.","steps":[{"title":"Playing to the Click","body":"The metronome/click is non-negotiable in most studio settings. Practice at ALL tempos, especially slow (60 bpm and below) where the space between clicks is large and your internal time is most exposed. Play entire songs to a click alone; all timing errors are yours. When recording, listen for your relationship to the click: slightly behind feels relaxed and groovy; slightly ahead feels urgent."},{"title":"Tone Selection for Recording","body":"Recorded tone differs from live tone. Less gain than live; distortion compresses in recording and sounds smaller. Less low end below 80 Hz typically filtered; excessive bass creates mud with bass guitar and kick. More midrange presence; guitar role in mix is primarily midrange (200 Hz to 5 kHz). Record dry DI alongside miked amp for re-amping safety net."},{"title":"Performance Consistency","body":"Deliver the same part identically on multiple takes. Practice recording a 2-bar phrase four times; compare waveforms. Are dynamics, timing, and articulation consistent? Studio guitarists develop ability to reproduce performances with microscopic precision. This is professional reliability, not robotic playing."},{"title":"The Psychological Game","body":"The studio can be intimidating: clock running, engineer waiting, red recording light creating anxiety. Counter-strategies: request rough mix to practice with beforehand. Ask for click and guide track only in headphones. Take breaks between difficult passages. Accept that first take is often best despite imperfections; energy and freshness matter more than surgical precision."}],"tips":["Practice recording yourself at home weekly; red light anxiety is overcome only through repeated exposure","Play 10-20% fewer notes than you think necessary; studio recordings feel busier than they are; fewer well-placed notes record better","Learn to play to click at 60 bpm and 120 bpm; extremes expose different timing weaknesses"]}',
   null, null, 0, 40, true),

  ('a1c80000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000008',
   'Live Sound and Monitoring',
   'Understand PA systems, stage monitoring, in-ear monitors, amp placement, and getting great live guitar sound in any venue.',
   5, 'theory',
   '{"intro":"Your stage sound is not what the audience hears. Understanding the signal path from guitar to front-of-house PA and managing your own monitoring is essential for consistent live performance. This lesson covers amplifier placement, monitors, in-ear systems, and live sound compromises.","steps":[{"title":"Amplifier Placement and Stage Volume","body":"The guitar amp is directional; sound projects forward in a cone. Amp on floor pointing at your knees means what you hear differs dramatically from what the audience hears. Solutions: tilt amp back pointing at your ears, raise on stand or chair, or use amp shield (plexiglass baffle) to reduce stage volume while miking for PA. Lower stage volume is always better; it gives the sound engineer control and lets the band hear each other."},{"title":"Stage Monitors and Wedges","body":"Floor wedge monitors let you hear yourself on stage. Request only what you need: typically your guitar, lead vocals, and kick/snare for time reference. Too many instruments in the monitor create a wash harder to play with than silence. Position the wedge at your ears, not your knees. During soundcheck, ask for more me only after ensuring the overall mix is balanced."},{"title":"In-Ear Monitors (IEMs)","body":"IEMs provide consistent monitoring regardless of venue acoustics at significantly lower volume, protecting your hearing. Stereo IEM mix allows spatial placement: bass and kick center, guitars slightly off-center, backing vocals panned. Ambient mics feed crowd noise into IEMs preventing the disconnected isolated feeling. Custom-molded IEMs provide best isolation and bass response."},{"title":"The Front-of-House Relationship","body":"The FOH engineer controls what the audience hears. Build positive professional relationship: arrive early for soundcheck, have gear ready, communicate clearly and concisely (A bit more 2kHz in the guitar please), and trust the engineer judgment about overall mix balance. They hear the room; you cannot. A short professional soundcheck builds goodwill. The engineer is your ally; treat them as such."}],"tips":["Invest in high-quality earplugs (Etymotic, ACS) and wear them at every rehearsal and show; tinnitus is permanent and preventable","Learn basic audio terminology (frequency ranges, dB, gain vs. volume, compression, EQ bands) to communicate effectively with engineers","Arrive at soundcheck with a 30-second riff that covers your full frequency range to dial in EQ quickly"]}',
   null, null, 0, 40, true);

-- ============================================================
-- CHAPTER 9: Lifelong Learning & Mastery
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, accuracy_threshold, estimated_minutes, is_premium) values

  ('a1c90000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000009',
   'Advanced Ear Training',
   'Develop the ability to identify intervals, chord qualities, progressions, and melodies entirely by ear. The ultimate musicianship skill.',
   1, 'exercise',
   '{"intro":"Ear training is the meta-skill underpinning all musicianship. The ability to hear a melody and play it, recognize a chord progression, or transcribe a solo in real time separates competent guitarists from truly musical ones. This lesson provides systematic methods for developing advanced aural skills.","steps":[{"title":"Interval Recognition","body":"Master all intervals within one octave: unison, minor 2nd, major 2nd, minor 3rd, major 3rd, perfect 4th, tritone (aug 4th/dim 5th), perfect 5th, minor 6th, major 6th, minor 7th, major 7th, octave. Associate each with a familiar song opening: minor 2nd=Jaws theme, major 2nd=Happy Birthday, perfect 4th=Here Comes the Bride, perfect 5th=Star Wars theme, tritone=Maria (West Side Story). Practice identifying intervals ascending and descending daily."},{"title":"Chord Quality Recognition","body":"Identify chord quality by ear: major (bright, stable, happy), minor (dark, stable, sad), diminished (unstable, tense, wants resolution), augmented (floating, unsettled, dreamlike). Then add seventh chords: maj7 (major with dreamy quality), dom7 (major with bluesy tension), m7 (minor with added warmth), m7b5 (half-diminished, dark and tense), dim7 (fully diminished, symmetrical and dramatic). Test yourself with random chord playback daily."},{"title":"Progression Recognition","body":"Identify common progressions by ear: I-IV-V (blues/rock), I-V-vi-IV (pop), ii-V-I (jazz), i-bVII-bVI-V (minor rock). Listen for bass movement first; the bass line reveals the progression 80% of the time. Then identify chord qualities (major/minor/dominant). Then listen for characteristic voice leading (the 7th of ii resolving to 3rd of V). Practice with recordings in all 12 keys."},{"title":"Melodic Dictation","body":"Hear a melody once or twice and reproduce it on guitar from memory. Start with 4-bar phrases at slow tempos. Process: determine key, identify first note, hear direction and interval size for each subsequent note, determine rhythm by tapping foot. Gradually increase phrase length and complexity. This skill combines interval recognition, rhythmic dictation, and fretboard knowledge simultaneously."}],"tips":["Practice ear training 10-15 minutes daily; consistency matters far more than session length; the ear develops during sleep","Sing intervals before identifying them on guitar; the voice is the most direct connection to the ear","Use a dedicated ear training app (Functional Ear Trainer, Perfect Ear, EarMaster) for structured daily practice"]}',
   null, null, 75, 50, true),

  ('a1c90000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000009',
   'Transcription Mastery',
   'Take transcription to the advanced level: transcribe full solos, chord voicings, and arrangements with speed and accuracy.',
   2, 'exercise',
   '{"intro":"Transcription mastery means hearing a passage once or twice and being able to play it back accurately. It is the ultimate test of ear-hand coordination and the primary method by which all great musicians acquired their vocabulary. This lesson advances beyond basic transcription to full solo and arrangement transcription.","steps":[{"title":"Speed Transcription Drills","body":"Choose a 2-bar phrase from any recording. Listen exactly once. Sing it back from memory. Play it on guitar from memory. Notate it. Then check against the recording. Your accuracy on first listen measures your transcription ability. Practice daily with random phrases from different genres. Goal: 90%+ accuracy on first listen for diatonic phrases."},{"title":"Full Solo Transcription","body":"Transcribe an entire guitar solo: all notes, all articulations (bends, slides, vibrato placement, pick attack nuances), all rhythmic placements. Notate in standard notation and tablature. Analyze: what scales over which chords? What motifs are developed? What is the emotional arc? A complete solo transcription of 2-3 choruses should take 2-3 hours at the advanced level."},{"title":"Chord Voicing Transcription","body":"Transcribing chord voicings is harder than single notes because multiple frequencies must be isolated simultaneously. Strategy: identify the top note (soprano voice), then the bass note, then fill in inner voices. Use EQ filtering or slow-down software to isolate frequency ranges. Arpeggiate the chord on guitar to verify each note against the recording."},{"title":"Building a Transcription Library","body":"Maintain a personal transcription library: one solo or arrangement transcribed per week, every week, for a year. Fifty-two transcriptions from diverse players across genres. This library becomes your personal vocabulary source; patterns appearing across multiple transcriptions become part of your intuitive musical language. The difference between a good player and a great one is often measured in transcriptions completed."}],"tips":["Transcribe a variety of instruments, not just guitar; saxophone, piano, and vocal lines teach phrasing guitarists rarely discover on their own","Focus on articulation as much as notes; a bend that starts slow and speeds up is a different musical gesture than one that is linear","Organize transcriptions by concept (enclosures, diminished vocabulary, Lydian dominant lines) to build a categorized vocabulary library"]}',
   null, null, 80, 55, true),

  ('a1c90000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000009',
   'Developing a Teaching Method',
   'Learn to teach guitar effectively: curriculum design, diagnosing student problems, communication skills, and pedagogical principles.',
   3, 'theory',
   '{"intro":"Teaching guitar is a distinct skill from playing guitar. The ability to diagnose why a student is struggling, communicate concepts clearly at their level, and design a progressive curriculum transforms you from a guitarist who gives tips into an effective educator. This lesson covers pedagogical principles for guitar instruction.","steps":[{"title":"Diagnosing Student Problems","body":"Most student struggles have root causes different from their apparent symptoms. A student who cannot play barre chords may have thumb position issues rather than finger strength problems. A student with poor rhythm may have never internalized the beat, not have finger coordination issues. Diagnose by watching and listening beyond the obvious: hand position, tension patterns, and fundamental understanding gaps."},{"title":"Scaffolding: Building Progressive Steps","body":"Scaffolding means breaking skills into incremental steps where each step is achievable from the previous one. Teaching sweep picking does not begin with five-string arpeggios; it begins with the sweeping motion on two strings. Every advanced technique has a scaffold of prerequisite skills. Design a curriculum where each lesson builds directly on the previous one with a clear progression visible to the student."},{"title":"Communication: Explanations That Work","body":"The best explanation is the one the student understands, not the most technically precise one. Use multiple communication modes: verbal explanation, physical demonstration, visual diagrams, metaphors and analogies (barre chord = your index finger is a temporary capo). Check for understanding by having the student explain the concept back to you. Adapt your language to the student level."},{"title":"Building Student Confidence and Autonomy","body":"The goal of teaching is to make yourself unnecessary. Teach students how to practice, not just what to practice. Teach them how to diagnose their own problems. Teach them how to find and evaluate learning resources independently. A student who leaves each lesson knowing what to practice, how to practice it, and why it matters is on the path to lifelong musical growth."}],"tips":["Record yourself teaching a concept and review it; you will notice unclear explanations and missed opportunities for better examples","Teach one beginner student while you are an advanced player; the experience of explaining fundamentals deepens your own understanding","Study pedagogical methods outside music; sports coaching, language instruction, and mathematics education all have applicable principles"]}',
   null, null, 0, 40, true),

  ('a1c90000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000009',
   'Building Your Repertoire',
   'Develop a systematic approach to learning, maintaining, and performing a diverse repertoire of pieces and songs.',
   4, 'exercise',
   '{"intro":"A guitarist repertoire is their musical identity. Building a balanced, performable repertoire requires systematic learning, maintenance practice, and strategic expansion. This lesson provides frameworks for repertoire development across genres and difficulty levels.","steps":[{"title":"Repertoire Categories","body":"Build four repertoire categories: (1) Performance-ready pieces polished for any audience at any time (5-10 pieces). (2) In-progress pieces being actively learned (3-5 pieces). (3) Maintenance pieces previously learned that need periodic refresh (10-20 pieces). (4) Aspirational pieces beyond current ability that motivate growth (3-5 pieces). Track each piece status, last performance date, and areas needing work."},{"title":"The Learning System","body":"For each new piece: (1) Listen to multiple recordings to internalize the interpretation. (2) Analyze the form, key, and technical challenges before touching the guitar. (3) Break into sections; learn the hardest section first, not the beginning. (4) Practice hands separately before combining for complex classical pieces. (5) Record each section when you think it is ready; the recording reveals what your ears miss while playing."},{"title":"Maintenance Practice","body":"Repertoire decays without maintenance. Schedule a repertoire review session weekly where you play through maintenance pieces once each. Rotate pieces so every piece in the maintenance category is played at least monthly. Pieces that consistently degrade need dedicated re-practice; pieces that stay solid need less frequent review. Track which pieces hold and which fade to optimize review scheduling."},{"title":"Performance Preparation","body":"A piece is not performance-ready when you can play it correctly; it is performance-ready when you cannot play it incorrectly. Stress-test: play the piece at 120% tempo; play it starting from any bar; play it while holding a conversation; play it first thing in the morning with cold hands. If the piece survives all stress tests, it is ready. A performance-ready repertoire of 10 pieces is more valuable than 50 half-learned pieces."}],"tips":["Keep a repertoire journal: date learned, key, tempo, technical challenges, performance history, and notes for improvement","Perform your repertoire for anyone who will listen; each performance reveals weaknesses that practice alone never exposes","Balance your repertoire across genres, keys, tempos, and techniques; a diverse repertoire makes you a more versatile and employable musician"]}',
   null, null, 75, 50, true),

  ('a1c90000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000009',
   'Musical Vision and Artistic Identity',
   'Define your artistic voice: influences, aesthetics, goals, and the lifelong pursuit of meaningful musical expression.',
   5, 'theory',
   '{"intro":"Technical mastery is meaningless without artistic purpose. Developing a musical vision means understanding what you want to say through music and how your unique combination of influences, experiences, and sensibilities creates a voice no one else possesses. This lesson guides you through defining and refining your artistic identity.","steps":[{"title":"Mapping Your Influences","body":"List the 10 guitarists and 10 non-guitarist musicians who have most deeply affected you. For each, identify specifically what moves you: tone, phrasing, harmonic choices, rhythmic feel, emotional range, compositional style. Then identify the intersections where multiple influences overlap; these intersections are the foundation of your unique voice. No one else shares your exact combination of influences in your exact proportions."},{"title":"Defining Your Aesthetic Values","body":"Articulate what you value in music. Is it emotional directness or intellectual complexity? Raw energy or refined precision? Tradition or innovation? Melody or rhythm? Space or density? There are no right answers, but clarity about your values guides every musical decision: which projects to pursue, which techniques to develop, which musical relationships to cultivate."},{"title":"The Creative Practice","body":"Artistic identity is not discovered; it is built through consistent creative practice. Set aside time each week for unstructured musical exploration: improvise freely, experiment with sounds, compose without judgment, combine influences in ways that should not work. Treat this creative time as seriously as technical practice. The goal is not to produce finished work but to explore the boundaries of your musical identity."},{"title":"Lifelong Growth and Evolution","body":"Artistic identity evolves. The guitarist you are at 20 is not the guitarist you will be at 40, and should not be. Stay curious. Study music outside your comfort zone. Collaborate with musicians who challenge you. Revisit influences you dismissed years ago; you may hear them differently now. The goal is not to arrive at a fixed identity but to remain in a state of continual musical growth, always reaching toward the next version of yourself."}],"tips":["Write an artistic statement: one paragraph describing the music you want to create and why it matters; revisit and revise it annually","Record an album of original music, however modest; the act of completing a body of work crystallizes your artistic identity more than any amount of practice","Seek out older musicians whose careers you admire and ask them about their artistic journey; their perspective on long-term growth is invaluable"]}',
   null, null, 0, 40, true);
